// ── Hints ─────────────────────────────────────────────────────────────────────
// Every game gets a "Hint?" button. A subscriber may reveal up to HINT_MAX hints
// per game per day; the count is persisted (localStorage, CT-day-scoped) so it
// survives reloads and can't be farmed by refreshing. Hint copy is drawn from the
// puzzle's own content — it never affects scoring.
const HINT_MAX = 3;

function clipText(s, n) {
  s = String(s == null ? "" : s).trim();
  return s.length > n ? s.slice(0, n).replace(/\s+\S*$/, "") + "…" : s;
}

// Stable, puzzle-level hints (Rackl · Signal Drop · The Stack · Dark Fiber),
// revealed in order and capped at HINT_MAX.
function hintsForPuzzle(gameType, puzzle) {
  if (!puzzle) return [];
  const out = [];
  if (gameType === "Rackl") {
    (puzzle.groups || []).forEach(g => { if (g && g.label) out.push(`One of the groups is “${g.label}”.`); });
  } else if (gameType === "Signal Drop") {
    // Live puzzles ship pre-built hints (server strips `word`, so the client
    // can't derive the first-letter hint itself). Mock/legacy puzzles that still
    // carry `word` fall back to building the hints locally.
    if (Array.isArray(puzzle.hints) && puzzle.hints.length) {
      return puzzle.hints.filter(Boolean).slice(0, HINT_MAX);
    }
    if (puzzle.hint1) out.push(String(puzzle.hint1));
    if (puzzle.hint2) out.push(String(puzzle.hint2));
    const w = puzzle.word ? String(puzzle.word).toUpperCase() : "";
    if (w) out.push(`It starts with “${w[0]}” and is ${w.length} letters long.`);
  } else if (gameType === "The Stack") {
    if (puzzle.metric) out.push(`Rank by ${puzzle.metric}.`);
    const co = Array.isArray(puzzle.correctOrder) ? puzzle.correctOrder : null;
    const items = Array.isArray(puzzle.items) ? puzzle.items : null;
    if (co && items) {
      if (items[co[0]] != null) out.push(`“${items[co[0]]}” belongs at the top (#1).`);
      const last = co[co.length - 1];
      if (items[last] != null && last !== co[0]) out.push(`“${items[last]}” belongs at the bottom.`);
    }
  } else if (gameType === "Dark Fiber") {
    (puzzle.pairs || []).forEach(p => { if (p && p.term && p.def) out.push(`${p.term} → ${clipText(p.def, 64)}`); });
  }
  return out.filter(Boolean).slice(0, HINT_MAX);
}

// Per-question hints (Circuit · The Brief · Frequency) for the CURRENT question.
// Multiple-choice → eliminate wrong options, then the explanation; True/False →
// the explanation. The caller remounts via key={qIdx} so each question gets its
// own reveals, all drawing from the shared per-game daily budget.
function hintsForQuestion(q) {
  if (!q) return [];
  const out = [];
  if (Array.isArray(q.options) && q.options.length > 2 && typeof q.correct === "number") {
    const wrong = q.options.filter((_, i) => i !== q.correct);
    if (wrong[0]) out.push(`It isn’t “${clipText(wrong[0], 60)}”.`);
    if (wrong[1]) out.push(`It also isn’t “${clipText(wrong[1], 60)}”.`);
  }
  if (q.explanation) out.push(clipText(q.explanation, 150));
  return out.filter(Boolean).slice(0, HINT_MAX);
}

// Shared Hint control. Reveals `hints` one at a time, spending from a per-game
// daily budget of HINT_MAX shared across every press (persisted). Renders nothing
// when there are no hints to give.
function HintControl({ gameType, hints }) {
  const list = Array.isArray(hints) ? hints.filter(Boolean) : [];
  const storageKey = `faraday_hints_${TODAY}_${gameType}`;
  const [usedTotal, setUsedTotal] = useState(0);   // budget spent across the game today
  const [localShown, setLocalShown] = useState(0); // revealed within this instance

  useEffect(() => {
    try {
      const v = parseInt(localStorage.getItem(storageKey) || "0", 10);
      if (!Number.isNaN(v)) setUsedTotal(v);
    } catch { /* storage disabled */ }
  }, [storageKey]);

  if (list.length === 0) return null;

  const remaining = Math.max(0, HINT_MAX - usedTotal);
  const canReveal = remaining > 0 && localShown < list.length;

  function reveal() {
    if (!canReveal) return;
    setLocalShown(n => n + 1);
    setUsedTotal(prev => {
      const next = prev + 1;
      try { localStorage.setItem(storageKey, String(next)); } catch { /* ignore */ }
      return next;
    });
  }

  const label =
    remaining === 0 ? "No hints left" :
    localShown >= list.length ? "Hint shown ✓" :
    `Hint? (${remaining} left)`;

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"8px", alignItems:"center", width:"100%" }}>
      {localShown > 0 && (
        <div style={{ width:"100%", maxWidth:"420px", display:"flex", flexDirection:"column", gap:"6px" }}>
          {list.slice(0, localShown).map((h, i) => (
            <div key={i} style={{
              fontSize:"12px", color:C.amber, lineHeight:1.5, ...mono,
              background:"rgba(245,158,11,0.08)", border:"1px solid rgba(245,158,11,0.25)",
              borderRadius:"6px", padding:"8px 12px",
            }}>
              <span style={{ color:C.muted }}>Hint {i + 1}:</span> {h}
            </div>
          ))}
        </div>
      )}
      <Btn onClick={reveal} variant="ghost" small disabled={!canReveal}>{label}</Btn>
    </div>
  );
}

// Uniform nav pill used in the header for all four nav items + sign-in button.
// Track viewport width so labels can be hidden on mobile (≤430px) without a
// layout shift. SSR-safe: starts desktop-first (1024) and syncs on mount.
function useWindowWidth() {
  const [w, setW] = useState(1024);
  useEffect(() => {
    const onResize = () => setW(window.innerWidth);
    onResize();
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);
  return w;
}

// Icon-first nav button (FAR-207). Renders a processed emblem image (40×40 in
// the header, 80×80 expanded) on the #0D1810 canvas plus an optional chrome
// label that hides on mobile. Three visual states: default (transparent border,
// muted label) · hover (lighter forest tint + gold border, label→gold) · active
// (forest-green tint bg + gold border + 2px gold underline tab).
function NavPill({ icon, letter, label, onClick, active, hideLabel, size = 40, badge, style: extraStyle }) {
  const [hover, setHover] = useState(false);
  const interactive = typeof onClick === "function";
  const lit = active || (hover && interactive);
  return (
    <button
      type="button"
      onClick={onClick}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      className="nav-pill"
      title={label}
      aria-label={badge != null ? `${label}: ${badge}` : label}
      style={{
        position: "relative",
        minWidth: "52px",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: "3px",
        background: active
          ? "rgba(28,52,36,0.55)"          // forest-green tint
          : (hover && interactive)
          ? "rgba(28,52,36,0.30)"          // lighter forest tint
          : "transparent",
        border: "1px solid transparent",   // no gold box — active is marked by the underline tab
        WebkitTapHighlightColor: "transparent",
        borderRadius: "8px",
        padding: "5px 6px 6px",
        cursor: interactive ? "pointer" : "default",
        lineHeight: 1,
        overflow: "visible",               // allow the count badge to sit outside the icon
        transition: "all 0.15s",
        ...extraStyle,
      }}
    >
      {badge != null && (
        <span
          aria-hidden="true"
          style={{
            position: "absolute",
            top: "1px",
            right: "6px",
            minWidth: "16px",
            height: "16px",
            padding: "0 4px",
            borderRadius: "8px",
            background: C.gold,
            color: C.forest,
            fontSize: "10px",
            fontWeight: 700,
            lineHeight: "16px",
            textAlign: "center",
            ...mono,
            boxShadow: "0 0 0 1.5px rgba(28,52,36,0.9)",
          }}
        >
          {badge}
        </span>
      )}
      {letter ? (
        // Simplified nav mark: a white capital letter (D · L · A) instead of the
        // 3D emblem. Active/hover is still shown by the underline tab + tint.
        <span
          aria-hidden="true"
          style={{
            width: `${size}px`,
            height: `${size}px`,
            display: "grid",
            placeItems: "center",
            color: C.white,
            fontWeight: 800,
            fontSize: `${Math.round(size * 0.62)}px`,
            lineHeight: 1,
            ...serif,
          }}
        >
          {letter}
        </span>
      ) : (
        <img
          src={icon}
          alt=""
          width={size}
          height={size}
          style={{
            width: `${size}px`,
            height: `${size}px`,
            objectFit: "cover",
            objectPosition: "center",
            borderRadius: "6px",
            display: "block",
            filter: NAV_ICON_FILTER,
          }}
        />
      )}
      {!hideLabel && (
        <span
          className="nav-lbl"
          style={{
            ...mono,
            fontSize: "8px",
            letterSpacing: "0.1em",
            textTransform: "uppercase",
            color: lit ? C.gold : C.muted,
            transition: "color 0.15s",
          }}
        >
          {label}
        </span>
      )}
      {active && (
        <span
          aria-hidden="true"
          style={{
            position: "absolute",
            left: "12%",
            right: "12%",
            bottom: 0,
            height: "2px",
            background: C.gold,
            borderRadius: "1px",
          }}
        />
      )}
    </button>
  );
}

// ── Viral share — generated score card + device share/copy/download ───────────
const SITE_URL = "https://faraday-intelligence.ai";
const DC_URL = `${SITE_URL}/daily-challenge`;
// Public-facing share domain — the short, memorable URL we hand to recipients.
// faradaydailychallenge.com 301-redirects to the canonical /daily-challenge
// route, so deep links resolve while the shared text stays brandable.
const SHARE_URL = "https://www.faradaydailychallenge.com";

// Load an SVG-string into an <Image> for canvas drawing. Resolves null on any
// failure so a missing icon never blocks the card. Self-contained data URL ⇒
// the canvas stays untainted and toBlob keeps working.
function loadSvgImage(svg) {
  return new Promise((resolve) => {
    if (!svg || typeof Image === "undefined") return resolve(null);
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => resolve(null);
    img.src = "data:image/svg+xml;charset=utf-8," + encodeURIComponent(svg);
  });
}

// Rasterise the game's locked neon pictogram tile to a square PNG blob — this is
// the share image (NYT-Connections style: the score + Public ID ride in the share
// text, not baked into the image). Mirrors the on-screen GameIcon via
// gameIconSvgString, so the shared tile is the exact neon icon the player saw.
// The tile's rounded corners stay transparent, so it sits cleanly in any bubble.
// Returns null if canvas/toBlob is unavailable.
async function buildShareIconBlob(puzzleType, size = 640) {
  try {
    const img = await loadSvgImage(gameIconSvgString(puzzleType, size));
    if (!img) return null;
    const cv = document.createElement("canvas");
    cv.width = size; cv.height = size;
    const ctx = cv.getContext("2d");
    if (!ctx) return null;
    ctx.drawImage(img, 0, 0, size, size);
    return await new Promise((resolve) => cv.toBlob((b) => resolve(b), "image/png"));
  } catch { return null; }
}

// Device share cascade: Web Share w/ image → Web Share text → clipboard → download.
// Returns a short status word ("Shared" | "Copied" | "Saved" | "idle") for UI feedback.
async function shareViaDevice({ title, text, url, blob, filename }) {
  const full = url ? `${text} ${url}` : text;
  try {
    if (blob && typeof File !== "undefined" && navigator.canShare) {
      const file = new File([blob], filename || "faraday.png", { type: "image/png" });
      if (navigator.canShare({ files: [file] })) {
        await navigator.share({ files: [file], title, text: full });
        return "Shared";
      }
    }
    if (navigator.share) { await navigator.share({ title, text, url }); return "Shared"; }
    if (navigator.clipboard?.writeText) { await navigator.clipboard.writeText(full); return "Copied"; }
  } catch (e) {
    if (e && e.name === "AbortError") return "idle"; // user cancelled the sheet
  }
  try {
    if (blob) {
      const a = document.createElement("a");
      a.href = URL.createObjectURL(blob); a.download = filename || "faraday.png";
      a.click(); URL.revokeObjectURL(a.href);
      return "Saved";
    }
  } catch { /* noop */ }
  return "idle";
}

// ── Score display ─────────────────────────────────────────────────────────────
function ScoreCard({ score, dailyTotal, puzzleType, puzzleName, publicId, domain, streak, onShare, onNext }) {
  const mark = score >= 130 ? "◆" : score >= 100 ? "◇" : score >= 75 ? "✦" : "◎";
  const [shareLabel, setShareLabel] = useState("↑ Share Result");
  async function handleShare() {
    setShareLabel("…");
    const blob = await buildShareIconBlob(puzzleType);
    // Deep-link back to the game so the receiver can play; carry the puzzle's
    // unique Public ID (when set) so the share points at this exact puzzle.
    const url = `${SHARE_URL}?game=${encodeURIComponent(puzzleType)}${publicId ? `&p=${encodeURIComponent(publicId)}` : ""}`;
    // Simple NYT-Connections-style headline: game + score, Public ID on its own
    // line. The neon-icon image carries the brand; no stats baked into the copy.
    const text = `Faraday Daily Challenge - ${puzzleType} Score - ${score}${publicId ? `\n${publicId}` : ""}`;
    const status = await shareViaDevice({
      title: "Faraday Daily Challenge", text, url, blob,
      filename: `faraday-${puzzleType.toLowerCase().replace(/\s+/g, "-")}.png`,
    });
    onShare?.();
    setShareLabel(
      status === "Shared" ? "Shared ✓" : status === "Copied" ? "Link copied ✓" :
      status === "Saved" ? "Saved ✓" : "↑ Share Result"
    );
    if (status !== "idle") setTimeout(() => setShareLabel("↑ Share Result"), 2500);
  }
  return (
    <div style={{ textAlign:"center", display:"flex", flexDirection:"column", alignItems:"center", gap:"20px" }}>
      <div style={{ fontSize:"48px", color:C.gold }}>{mark}</div>
      <div>
        <div style={{ display:"flex", alignItems:"baseline", justifyContent:"center", gap:"2px" }}>
          <div style={{ fontSize:"48px", fontWeight:800, color:C.gold, letterSpacing:"-0.04em", ...sans }}>{score}</div>
          <div style={{ fontSize:"22px", fontWeight:500, color:C.sage, letterSpacing:"-0.02em", ...sans }}>
            /{dailyTotal}
          </div>
        </div>
        <div style={{ fontSize:"11px", color:C.muted, marginTop:"4px", ...mono }}>this game / today · {puzzleType}</div>
      </div>
      <div style={{ background:`rgba(196,146,42,0.06)`, border:`1px solid rgba(196,146,42,0.2)`,
        borderRadius:"8px", padding:"12px 20px", display:"flex", gap:"24px" }}>
        <div style={{ textAlign:"center" }}>
          <div style={{ fontSize:"16px", fontWeight:700, color:C.gold, ...sans }}>{streak}</div>
          <div style={{ fontSize:"11px", color:C.muted, ...mono }}>day streak</div>
        </div>
      </div>
      <div style={{ display:"flex", gap:"10px" }}>
        <Btn onClick={handleShare} variant="ghost" small>{shareLabel}</Btn>
        <Btn onClick={onNext}>Play Another →</Btn>
      </div>
      <div style={{ fontSize:"11px", color:C.muted, ...mono }}>
        Score includes {getStreakMultiplier(streak).mult}× streak multiplier
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME: RACKL — Connections-style tile grouping
// ══════════════════════════════════════════════════════════════════════════════
// Connections-style mistake budget: 4 wrong groupings ends the round (matches the
// four mistake dots shown in the footer).
const RACKL_MAX_MISTAKES = 4;

function GameRackl({ puzzle, streak, onComplete, dailyTotal }) {
  const allItems = puzzle.groups.flatMap((g, gi) => g.items.map((item, i) => ({ item, groupIdx:gi, id:`${gi}-${i}` })));
  const [tiles,    setTiles]    = useState(() => [...allItems].sort(() => Math.random()-0.5));
  const [selected, setSelected] = useState([]);
  const [solved,   setSolved]   = useState([]);
  const [mistakes, setMistakes] = useState(0);
  const [feedback, setFeedback] = useState(null);
  const [done,     setDone]     = useState(false);
  const [lost,     setLost]     = useState(false);
  const [scoreVal, setScoreVal] = useState(null);
  const startTime = useRef(Date.now());

  function toggle(id) {
    if (solved.includes(id)) return;
    setSelected(prev => prev.includes(id) ? prev.filter(x=>x!==id) : prev.length < 4 ? [...prev, id] : prev);
  }

  function submit() {
    if (selected.length !== 4) return;
    const groups = selected.map(id => tiles.find(t=>t.id===id).groupIdx);
    if (groups.every(g => g === groups[0])) {
      const newSolved = [...solved, ...selected];
      setSolved(newSolved);
      setSelected([]);
      setFeedback({ type:"correct", label:puzzle.groups[groups[0]].label });
      setTimeout(() => setFeedback(null), 1500);
      if (newSolved.length === 16) {
        const elapsed = (Date.now() - startTime.current) / 1000;
        const perfect = mistakes === 0;
        const s = calcScore({ basePoints:16, maxPoints:16, timeElapsed:elapsed, timeLimit:180, perfect, streak });
        setScoreVal(s);
        setDone(true);
      }
    } else {
      const newMistakes = mistakes + 1;
      setMistakes(newMistakes);
      setSelected([]);
      if (newMistakes >= RACKL_MAX_MISTAKES) {
        // Out of guesses — end the round and score partial credit for any groups
        // already solved (no perfect bonus on a loss).
        const elapsed = (Date.now() - startTime.current) / 1000;
        const s = calcScore({ basePoints:solved.length, maxPoints:16, timeElapsed:elapsed, timeLimit:180, perfect:false, streak });
        setFeedback(null);
        setScoreVal(s);
        setLost(true);
        setDone(true);
      } else {
        setFeedback({ type:"wrong" });
        setTimeout(() => setFeedback(null), 800);
      }
    }
  }

  if (done) return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      {lost && (
        <>
          <div style={{ ...mono, fontSize:"12px", color:C.red, textAlign:"center" }}>
            Out of guesses ({RACKL_MAX_MISTAKES} mistakes) — here&rsquo;s the full board:
          </div>
          {puzzle.groups.map((g, gi) => (
            <div key={gi} style={{ background:g.color, borderRadius:"8px", padding:"12px 16px",
              display:"flex", alignItems:"center", gap:"12px" }}>
              <span style={{ fontSize:"11px", fontWeight:700, color:g.textColor, letterSpacing:"0.06em", ...mono }}>{g.label}</span>
              <span style={{ fontSize:"11px", color:g.textColor, opacity:0.85, ...mono }}>{g.items.join(" · ")}</span>
            </div>
          ))}
        </>
      )}
      <ScoreCard score={scoreVal} dailyTotal={(dailyTotal || 0) + scoreVal} puzzleType="Rackl" domain={puzzle.domain} puzzleName={puzzle.name} publicId={puzzle.__publicId}
        streak={streak} onShare={()=>{}} onNext={()=>onComplete(scoreVal, { solvedGroups: puzzle.groups.map(g => g.label), mistakes })}
        isNew7Day={streak===6} />
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      {/* Solved groups — iterate over ALL groups by their ORIGINAL index so the
          label and items stay aligned. (A prior filter().map() reindexed gi to
          the filtered position, mislabelling any solved group after the first.) */}
      {puzzle.groups.map((g, gi) => {
        const groupSolved = solved.some(id => tiles.find(t=>t.id===id)?.groupIdx === gi);
        if (!groupSolved) return null;
        const solvedItems = tiles.filter(t => t.groupIdx === gi).map(t => t.item);
        return (
          <div key={gi} style={{ background:g.color, borderRadius:"8px", padding:"12px 16px",
            display:"flex", alignItems:"center", gap:"12px" }}>
            <span style={{ fontSize:"11px", fontWeight:700, color:g.textColor, letterSpacing:"0.06em", ...mono }}>{g.label}</span>
            <span style={{ fontSize:"11px", color:g.textColor, opacity:0.85, ...mono }}>{solvedItems.join(" · ")}</span>
          </div>
        );
      })}

      {/* Active tiles — crème background for readability */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:"8px" }}>
        {tiles.filter(t => !solved.includes(t.id)).map(t => {
          const isSelected = selected.includes(t.id);
          return (
            <button key={t.id} onClick={() => toggle(t.id)} style={{
              background: isSelected ? `rgba(196,146,42,0.2)` : C.cream,
              border: `2px solid ${isSelected ? C.gold : "rgba(28,52,36,0.15)"}`,
              borderRadius:"8px", padding:"14px 8px",
              cursor:"pointer", transition:"all 0.12s",
              transform: isSelected ? "translateY(-2px)" : "none",
              boxShadow: isSelected ? `0 4px 12px rgba(196,146,42,0.2)` : "none",
            }}>
              <span style={{ fontSize:"13px", fontWeight:600, color: isSelected ? C.gold : C.black,
                lineHeight:1.3, textAlign:"center", display:"block", ...sans }}>{t.item}</span>
            </button>
          );
        })}
      </div>

      {feedback && (
        <div style={{ textAlign:"center", fontSize:"11px", ...mono,
          color: feedback.type==="correct" ? C.green : C.red,
          background: feedback.type==="correct" ? "rgba(74,222,128,0.08)" : "rgba(248,113,113,0.08)",
          border:`1px solid ${feedback.type==="correct" ? "rgba(74,222,128,0.3)" : "rgba(248,113,113,0.3)"}`,
          borderRadius:"6px", padding:"8px" }}>
          {feedback.type==="correct" ? `✓ ${feedback.label}` : "✗ Not quite — try again"}
        </div>
      )}

      <HintControl gameType="Rackl" hints={hintsForPuzzle("Rackl", puzzle)} />

      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
        <div style={{ display:"flex", gap:"6px" }}>
          {[...Array(RACKL_MAX_MISTAKES)].map((_, i) => (
            <div key={i} style={{ width:"10px", height:"10px", borderRadius:"50%",
              background: i < mistakes ? C.red : C.dim }} />
          ))}
          <span style={{ fontSize:"11px", color:C.muted, marginLeft:"6px", ...mono }}>{mistakes}/{RACKL_MAX_MISTAKES} mistakes</span>
        </div>
        <Btn onClick={submit} disabled={selected.length !== 4}>
          Submit {selected.length}/4
        </Btn>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME: SIGNAL DROP — Wordle-style
// ══════════════════════════════════════════════════════════════════════════════
function GameSignalDrop({ puzzle, streak, onComplete, dailyTotal }) {
  // Live puzzles arrive WITHOUT the answer (`word` is stripped server-side and
  // guesses are validated at /api/challenge/guess). Mock/legacy puzzles still
  // carry `word` and are validated locally. `localWord` decides which path we
  // take; `wordLen` drives the grid either way.
  const localWord  = puzzle.word ? normalizeWord(puzzle.word) : null;
  const wordLen    = localWord ? localWord.length : Number(puzzle.wordLength) || 0;
  const maxGuesses = SIGNAL_MAX_GUESSES;

  const [guesses, setGuesses]   = useState([]);   // submitted guess strings
  const [results, setResults]   = useState([]);   // per-guess state arrays
  const [current, setCurrent]   = useState("");
  const [won,     setWon]       = useState(false);
  const [lost,    setLost]      = useState(false);
  const [revealed,setRevealed]  = useState(null);  // answer, only once game over
  const [scoreVal,setScoreVal]  = useState(null);
  const [checking,setChecking]  = useState(false); // server round-trip in flight
  const [error,   setError]     = useState(null);
  const startTime  = useRef(Date.now());

  function addLetter(l) {
    if (current.length < wordLen && !won && !lost && !checking) setCurrent(c => c+l);
  }
  function removeLetter() { if (!checking) setCurrent(c => c.slice(0,-1)); }

  // Commit a validated guess (from either the local or server path) and advance
  // terminal state. `answerMaybe` is the revealed answer or null.
  function applyResult(newGuesses, states, correct, answerMaybe) {
    setGuesses(newGuesses);
    setResults(r => [...r, states]);
    setCurrent("");
    if (answerMaybe) setRevealed(normalizeWord(answerMaybe));
    if (correct) {
      setWon(true);
      const elapsed = (Date.now() - startTime.current) / 1000;
      const perfect = newGuesses.length === 1;
      const baseP   = Math.max(0, maxGuesses - newGuesses.length + 1);
      setScoreVal(calcScore({ basePoints:baseP, maxPoints:maxGuesses, timeElapsed:elapsed, timeLimit:300, perfect, streak }));
    } else if (newGuesses.length >= maxGuesses) {
      setLost(true);
      setScoreVal(10);
    }
  }

  async function submitGuess() {
    if (checking || won || lost) return;
    if (current.length !== wordLen || wordLen === 0) return;
    const guess = normalizeWord(current);
    const newGuesses = [...guesses, guess];

    // Local path (mock / offline): validate against the in-memory word.
    if (localWord) {
      const { states, correct } = evaluateGuess(localWord, guess);
      const done = correct || newGuesses.length >= maxGuesses;
      applyResult(newGuesses, states, correct, done ? localWord : null);
      return;
    }

    // Server path (live): the answer never left the server. Post the full guess
    // list and get back per-letter feedback (and the answer only once over).
    setChecking(true);
    setError(null);
    try {
      const res = await fetch("/api/challenge/guess", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ gameType: "Signal Drop", publicId: puzzle.__publicId, guesses: newGuesses }),
      });
      if (!res.ok) throw new Error(`guess check failed (${res.status})`);
      const data = await res.json();
      applyResult(newGuesses, Array.isArray(data.states) ? data.states : [], !!data.correct, data.answer || null);
    } catch {
      // Don't consume the guess on a network error — let the player retry.
      setError("Couldn’t check that guess. Check your connection and try again.");
    } finally {
      setChecking(false);
    }
  }

  const tileColors = { correct:"#1C3424", present:"#5A4010", absent:"#2A2520", empty:"rgba(255,255,255,0.03)" };
  const tileText   = { correct:C.green, present:C.amber, absent:C.muted, empty:C.dim };

  // Keyboard colouring is derived from the per-guess feedback we've accumulated
  // (server- or locally-computed) — never from the answer, which the client may
  // not have. Precedence: correct > present > absent.
  const letterState = {};
  guesses.forEach((g, gi) => {
    (results[gi] || []).forEach((st, ci) => {
      const L = g[ci];
      if (!L) return;
      if (st === "correct") letterState[L] = "correct";
      else if (st === "present" && letterState[L] !== "correct") letterState[L] = "present";
      else if (st === "absent" && !letterState[L]) letterState[L] = "absent";
    });
  });

  if (won || lost) return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px", alignItems:"center" }}>
      {lost && revealed && (
        <div style={{ ...mono, fontSize:"13px", color:C.muted, textAlign:"center" }}>
          The word was <span style={{ color:C.text, fontWeight:700 }}>{revealed}</span>
        </div>
      )}
      <ScoreCard score={scoreVal} dailyTotal={(dailyTotal || 0) + scoreVal} puzzleType="Signal Drop" domain={puzzle.domain} puzzleName={revealed || puzzle.name} publicId={puzzle.__publicId}
        streak={streak} onShare={()=>{}}
        onNext={()=>onComplete(scoreVal, { guesses, results, word: revealed || localWord || "", won })}
        isNew7Day={streak===6} />
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px", alignItems:"center" }}>
      <div style={{ fontSize:"14px", color:C.text, textAlign:"center", lineHeight:1.6, ...mono, maxWidth:"380px" }}>
        {puzzle.clue}
      </div>

      {/* Grid — tiles flex-shrink so long words (e.g. 11-letter SOVEREIGNTY) stay
          on-screen in narrow portrait viewports instead of overflowing the right
          edge. maxWidth caps the row at the natural 44px tile size on wide screens,
          while flex:1 + aspectRatio keeps square tiles when space is tight. */}
      <div style={{ display:"flex", flexDirection:"column", gap:"4px", width:"100%",
        maxWidth:`${(wordLen || 6) * 48}px`, margin:"0 auto" }}>
        {[...Array(maxGuesses)].map((_, ri) => {
          const guess = guesses[ri] || (ri === guesses.length ? current : "");
          const rowStates = results[ri];
          return (
            <div key={ri} style={{ display:"flex", gap:"4px", width:"100%" }}>
              {[...Array(wordLen || 6)].map((_, ci) => {
                const state = rowStates ? (rowStates[ci] || "empty") : (guess[ci] ? "current" : "empty");
                return (
                  <div key={ci} style={{
                    flex:"1 1 0", minWidth:0, maxWidth:"44px", aspectRatio:"1 / 1", borderRadius:"4px",
                    background: state === "current" ? "rgba(255,255,255,0.06)" : tileColors[state] || tileColors.empty,
                    border: `2px solid ${state === "current" ? C.border : (state === "empty" ? C.dim : "transparent")}`,
                    display:"flex", alignItems:"center", justifyContent:"center",
                    fontSize:"clamp(13px, 4.5vw, 16px)", fontWeight:700, color: state === "current" ? C.text : (tileText[state] || C.muted),
                    transition:"all 0.2s", ...mono,
                  }}>
                    {guess[ci] || ""}
                  </div>
                );
              })}
            </div>
          );
        })}
      </div>

      {error && (
        <div style={{ fontSize:"12px", color:C.red, textAlign:"center", ...mono, maxWidth:"320px" }}>{error}</div>
      )}

      {/* Keyboard */}
      <div style={{ display:"flex", flexDirection:"column", gap:"5px", alignItems:"center", opacity: checking ? 0.6 : 1 }}>
        {[["Q","W","E","R","T","Y","U","I","O","P"],["A","S","D","F","G","H","J","K","L"],["ENTER","Z","X","C","V","B","N","M","⌫"]].map((row, ri) => (
          <div key={ri} style={{ display:"flex", gap:"4px" }}>
            {row.map(key => {
              const st = letterState[key];
              const isCorrect = st === "correct";
              const isPresent = st === "present";
              const used = st === "absent";
              return (
                <button key={key} disabled={checking} onClick={() => {
                  if (key === "ENTER") submitGuess();
                  else if (key === "⌫") removeLetter();
                  else addLetter(key);
                }} style={{
                  background: isCorrect ? "#1C3424" : isPresent ? "#5A4010" : used ? "#2A2520" : "rgba(255,255,255,0.07)",
                  border:"none", borderRadius:"4px",
                  width: key.length > 1 ? "52px" : "32px", height:"40px",
                  color: isCorrect ? C.green : isPresent ? C.amber : C.text,
                  fontSize:"13px", cursor: checking ? "default" : "pointer", fontWeight:600, ...mono,
                }}>{key}</button>
              );
            })}
          </div>
        ))}
      </div>

      <HintControl gameType="Signal Drop" hints={hintsForPuzzle("Signal Drop", puzzle)} />
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME: THE STACK — Drag-to-rank
// ══════════════════════════════════════════════════════════════════════════════
function GameStack({ puzzle, streak, onComplete, dailyTotal }) {
  const [order,    setOrder]    = useState(() => [...puzzle.items.map((_,i)=>i)].sort(()=>Math.random()-0.5));
  const [dragging, setDragging] = useState(null);
  const [submitted,setSubmitted]= useState(false);
  const [scoreVal, setScoreVal] = useState(null);
  const startTime = useRef(Date.now());

  // Reorder runs through a ref so rapid touchmove events never read a stale
  // `dragging` between renders. HTML5 draggable/onDragStart does NOT fire on
  // iOS Safari, so on iPhone/iPad the reorder runs entirely through the touch
  // handlers below; desktop keeps the native drag path.
  const dragRef = useRef(null);

  function beginDrag(idx) { dragRef.current = idx; setDragging(idx); }
  function moveTo(idx) {
    const from = dragRef.current;
    if (from === null || from === idx) return;
    setOrder(prev => {
      const next = [...prev];
      const item = next.splice(from, 1)[0];
      next.splice(idx, 0, item);
      return next;
    });
    dragRef.current = idx;
    setDragging(idx);
  }
  function endDrag() { dragRef.current = null; setDragging(null); }

  // Desktop HTML5 drag.
  function dragOver(e, idx) { e.preventDefault(); moveTo(idx); }

  // Touch drag (mobile/tablet): locate the row under the finger via
  // elementFromPoint and reorder to it. `touch-action: none` on each row stops
  // the page from scrolling while a tile is being dragged.
  function touchMove(e) {
    if (dragRef.current === null) return;
    const t = e.touches && e.touches[0];
    if (!t || typeof document === "undefined") return;
    const el = document.elementFromPoint(t.clientX, t.clientY);
    const row = el && el.closest ? el.closest("[data-stack-rank]") : null;
    if (!row) return;
    const idx = Number(row.getAttribute("data-stack-rank"));
    if (!Number.isNaN(idx)) moveTo(idx);
  }

  function submit() {
    // Score: count how many are in correct relative position
    const correct = order.filter((item, idx) => puzzle.correctOrder.indexOf(item) === idx).length;
    const perfect = correct === order.length;
    const elapsed = (Date.now() - startTime.current) / 1000;
    const s = calcScore({ basePoints:correct, maxPoints:order.length, timeElapsed:elapsed, timeLimit:120, perfect, streak });
    setScoreVal(s);
    setSubmitted(true);
  }

  if (submitted) return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      {order.map((itemIdx, rankIdx) => {
        const correctRank = puzzle.correctOrder.indexOf(itemIdx);
        const isCorrect   = correctRank === rankIdx;
        return (
          <div key={itemIdx} style={{
            background: isCorrect ? "rgba(74,222,128,0.08)" : "rgba(248,113,113,0.06)",
            border:`1px solid ${isCorrect ? "rgba(74,222,128,0.3)" : "rgba(248,113,113,0.2)"}`,
            borderRadius:"8px", padding:"12px 16px",
            display:"flex", justifyContent:"space-between", alignItems:"center" }}>
            <div style={{ display:"flex", gap:"12px", alignItems:"center" }}>
              <span style={{ fontSize:"11px", color:isCorrect?C.green:C.red, ...mono }}>#{rankIdx+1}</span>
              <span style={{ fontSize:"13px", color:C.text }}>{puzzle.items[itemIdx]}</span>
            </div>
            <div style={{ textAlign:"right" }}>
              <span style={{ fontSize:"11px", color:C.muted, ...mono }}>{puzzle.values?.[correctRank] || ""}</span>
              {!isCorrect && <div style={{ fontSize:"11px", color:C.red, ...mono }}>Correct: #{correctRank+1}</div>}
            </div>
          </div>
        );
      })}
      <div style={{ fontSize:"11px", color:C.muted, ...mono, textAlign:"center" }}>
        Ranking by: {puzzle.metric}
      </div>
      <ScoreCard score={scoreVal} dailyTotal={(dailyTotal || 0) + scoreVal} puzzleType="The Stack" domain={puzzle.domain} puzzleName={puzzle.name} publicId={puzzle.__publicId}
        streak={streak} onShare={()=>{}} onNext={()=>onComplete(scoreVal, { finalOrder: order, correctOrder: puzzle.correctOrder, items: puzzle.items, values: puzzle.values, metric: puzzle.metric })}
        isNew7Day={streak===6} />
    </div>
  );

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"12px" }}>
      <div style={{ fontSize:"11px", color:C.muted, textAlign:"center", ...mono }}>
        {puzzle.metric} — drag to reorder
      </div>
      {order.map((itemIdx, rankIdx) => (
        <div key={itemIdx}
          data-stack-rank={rankIdx}
          draggable
          onDragStart={() => beginDrag(rankIdx)}
          onDragOver={(e) => dragOver(e, rankIdx)}
          onDragEnd={endDrag}
          onTouchStart={() => beginDrag(rankIdx)}
          onTouchMove={touchMove}
          onTouchEnd={endDrag}
          onTouchCancel={endDrag}
          style={{
            background: dragging === rankIdx ? "rgba(196,146,42,0.1)" : C.surface,
            border:`1px solid ${dragging === rankIdx ? C.gold : C.border}`,
            borderRadius:"8px", padding:"14px 16px",
            display:"flex", alignItems:"center", gap:"14px",
            cursor:"grab", transition:"all 0.1s",
            touchAction:"none", userSelect:"none", WebkitUserSelect:"none",
            WebkitTouchCallout:"none",
            transform: dragging === rankIdx ? "scale(1.02)" : "none",
          }}>
          <span style={{ fontSize:"16px", color:C.dim, userSelect:"none" }}>⠿</span>
          <span style={{ fontSize:"14px", color:C.text, flex:1, ...sans }}>{puzzle.items[itemIdx]}</span>
          <span style={{ fontSize:"11px", color:C.muted, ...mono }}>#{rankIdx+1}</span>
        </div>
      ))}
      <HintControl gameType="The Stack" hints={hintsForPuzzle("The Stack", puzzle)} />

      <div style={{ marginTop:"8px" }}>
        <Btn onClick={submit}>Lock In Ranking →</Btn>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME: CIRCUIT — True/False sprint with timer
// ══════════════════════════════════════════════════════════════════════════════
function GameCircuit({ puzzle, streak, onComplete, dailyTotal }) {
  const [qIdx,    setQIdx]    = useState(0);
  const [answers, setAnswers] = useState([]);
  const [timeLeft,setTimeLeft]= useState(puzzle.timeLimit);
  const [done,    setDone]    = useState(false);
  const [scoreVal,setScoreVal]= useState(null);
  const [lastFeedback, setLastFeedback] = useState(null);
  const startTime = useRef(Date.now());

  useEffect(() => {
    if (done) return;
    const t = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) { clearInterval(t); finish(answers); return 0; }
        return prev - 1;
      });
    }, 1000);
    return () => clearInterval(t);
  }, [done, answers]);

  function answer(val) {
    const q   = puzzle.questions[qIdx];
    const ok  = (val === q.a);
    const newAnswers = [...answers, { q:q.q, given:val, correct:q.a, ok, explanation:q.explanation }];
    setLastFeedback(ok);
    setTimeout(() => {
      setLastFeedback(null);
      if (qIdx + 1 >= puzzle.questions.length) { finish(newAnswers); }
      else { setQIdx(i => i+1); setAnswers(newAnswers); }
    }, 600);
  }

  function finish(finalAnswers) {
    setDone(true);
    const correct = finalAnswers.filter(a => a.ok).length;
    const elapsed = (Date.now() - startTime.current) / 1000;
    const perfect = correct === puzzle.questions.length;
    const s = calcScore({ basePoints:correct, maxPoints:puzzle.questions.length, timeElapsed:elapsed, timeLimit:puzzle.timeLimit, perfect, streak });
    setScoreVal(s);
  }

  if (done && scoreVal !== null) return (
    <div style={{ display:"flex", flexDirection:"column", gap:"12px" }}>
      {answers.map((a, i) => (
        <div key={i} style={{
          background: a.ok ? "rgba(74,222,128,0.05)" : "rgba(248,113,113,0.05)",
          border:`1px solid ${a.ok ? "rgba(74,222,128,0.2)" : "rgba(248,113,113,0.2)"}`,
          borderRadius:"8px", padding:"12px 14px" }}>
          <div style={{ fontSize:"13px", color:C.text, marginBottom:"4px", ...sans }}>{a.q}</div>
          <div style={{ fontSize:"12px", color:a.ok?C.green:C.red, ...mono }}>
            {a.ok ? "✓ Correct" : `✗ You said ${a.given?"TRUE":"FALSE"} · Answer: ${a.correct?"TRUE":"FALSE"}`}
          </div>
          <div style={{ fontSize:"12px", color:C.muted, marginTop:"4px", lineHeight:1.5, ...mono }}>{a.explanation}</div>
        </div>
      ))}
      <ScoreCard score={scoreVal} dailyTotal={(dailyTotal || 0) + scoreVal} puzzleType="Circuit" domain={puzzle.domain} puzzleName={puzzle.name} publicId={puzzle.__publicId}
        streak={streak} onShare={()=>{}} onNext={()=>onComplete(scoreVal, { answers })}
        isNew7Day={streak===6} />
    </div>
  );

  const q = puzzle.questions[qIdx];
  const timePct = (timeLeft / puzzle.timeLimit) * 100;
  const timeColor = timePct > 50 ? C.green : timePct > 25 ? C.amber : C.red;

  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"20px" }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
        <SL>{qIdx+1} / {puzzle.questions.length}</SL>
        <span style={{ fontSize:"16px", fontWeight:700, color:timeColor, ...mono }}>{timeLeft}s</span>
      </div>
      <ProgressBar value={timeLeft} max={puzzle.timeLimit} color={timeColor}/>

      <div style={{ background:"rgba(255,255,255,0.03)", border:`1px solid ${C.border}`,
        borderRadius:"10px", padding:"24px", minHeight:"100px",
        display:"flex", alignItems:"center", justifyContent:"center",
        transition:"background 0.2s",
        backgroundColor: lastFeedback === true ? "rgba(74,222,128,0.06)" : lastFeedback === false ? "rgba(248,113,113,0.06)" : undefined }}>
        <p style={{ fontSize:"16px", color:C.text, textAlign:"center", margin:0, lineHeight:1.6, ...sans }}>{q.q}</p>
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"12px" }}>
        <button onClick={() => answer(true)} style={{
          background:"rgba(74,222,128,0.08)", border:"1px solid rgba(74,222,128,0.3)",
          borderRadius:"8px", padding:"18px", color:C.green,
          fontSize:"14px", fontWeight:700, cursor:"pointer", ...sans,
          transition:"all 0.1s",
        }}>TRUE ✓</button>
        <button onClick={() => answer(false)} style={{
          background:"rgba(248,113,113,0.08)", border:"1px solid rgba(248,113,113,0.3)",
          borderRadius:"8px", padding:"18px", color:C.red,
          fontSize:"14px", fontWeight:700, cursor:"pointer", ...sans,
          transition:"all 0.1s",
        }}>FALSE ✗</button>
      </div>

      <HintControl key={qIdx} gameType="Circuit" hints={hintsForQuestion(q)} />
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME: THE BRIEF — Read + comprehension
// ══════════════════════════════════════════════════════════════════════════════
function GameBrief({ puzzle, streak, onComplete, dailyTotal }) {
  const [phase,   setPhase]   = useState("read"); // read | quiz | done
  const [qIdx,    setQIdx]    = useState(0);
  const [answers, setAnswers] = useState([]);
  const [selected,setSelected]= useState(null);
  const [scoreVal,setScoreVal]= useState(null);
  const [timeLeft,setTimeLeft]= useState(puzzle.readTime);
  const startTime = useRef(Date.now());

  useEffect(() => {
    if (phase !== "read") return;
    const t = setInterval(() => {
      setTimeLeft(prev => { if (prev <= 0) { clearInterval(t); return 0; } return prev - 1; });
    }, 1000);
    return () => clearInterval(t);
  }, [phase]);

  function pickAnswer(idx) { setSelected(idx); }

  function nextQuestion() {
    const q = puzzle.questions[qIdx];
    const newAnswers = [...answers, { given:selected, correct:q.correct, ok:selected===q.correct, explanation:q.explanation }];
    setAnswers(newAnswers);
    setSelected(null);
    if (qIdx + 1 >= puzzle.questions.length) {
      const correct = newAnswers.filter(a => a.ok).length;
      const elapsed = (Date.now() - startTime.current) / 1000;
      const perfect = correct === puzzle.questions.length;
      const s = calcScore({ basePoints:correct, maxPoints:puzzle.questions.length, timeElapsed:elapsed, timeLimit:300, perfect, streak });
      setScoreVal(s);
      setPhase("done");
    } else {
      setQIdx(i => i+1);
    }
  }

  if (phase === "done") return (
    <div style={{ display:"flex", flexDirection:"column", gap:"12px" }}>
      {puzzle.questions.map((q, i) => (
        <div key={i} style={{
          background: answers[i]?.ok ? "rgba(74,222,128,0.05)" : "rgba(248,113,113,0.05)",
          border:`1px solid ${answers[i]?.ok ? "rgba(74,222,128,0.2)" : "rgba(248,113,113,0.2)"}`,
          borderRadius:"8px", padding:"12px 14px" }}>
          <div style={{ fontSize:"13px", color:C.text, marginBottom:"6px", ...sans }}>{q.q}</div>
          <div style={{ fontSize:"12px", color:answers[i]?.ok?C.green:C.red, ...mono }}>
            {answers[i]?.ok ? "✓ Correct" : `✗ Correct: "${q.options[q.correct]}"`}
          </div>
          <div style={{ fontSize:"12px", color:C.muted, marginTop:"4px", lineHeight:1.5, ...mono }}>{q.explanation}</div>
        </div>
      ))}
      <ScoreCard score={scoreVal} dailyTotal={(dailyTotal || 0) + scoreVal} puzzleType="The Brief" domain={puzzle.domain} puzzleName={puzzle.name} publicId={puzzle.__publicId}
        streak={streak} onShare={()=>{}} onNext={()=>onComplete(scoreVal, { answers })}
        isNew7Day={streak===6} />
    </div>
  );

  if (phase === "read") return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      <div style={{ display:"flex", justifyContent:"space-between" }}>
        <SL>Read the brief</SL>
        <span style={{ fontSize:"11px", color:C.muted, ...mono }}>{timeLeft}s suggested read time</span>
      </div>
      <div style={{ background:"rgba(255,255,255,0.025)", border:`1px solid ${C.border}`,
        borderRadius:"8px", padding:"20px", maxHeight:"320px", overflowY:"auto" }}>
        {puzzle.brief.split("\n\n").map((p, i) => (
          <p key={i} style={{ fontSize:"16px", color:C.text, lineHeight:1.7, marginBottom:"14px",
            marginTop:0, ...sans }}>{p}</p>
        ))}
      </div>
      <Btn onClick={() => setPhase("quiz")}>Ready — Take the Quiz →</Btn>
    </div>
  );

  const q = puzzle.questions[qIdx];
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      <SL>Question {qIdx+1} of {puzzle.questions.length}</SL>
      <div style={{ background:C.surface, border:`1px solid ${C.border}`,
        borderRadius:"8px", padding:"16px" }}>
        <p style={{ fontSize:"16px", color:C.text, margin:0, lineHeight:1.6, ...sans }}>{q.q}</p>
      </div>
      <div style={{ display:"flex", flexDirection:"column", gap:"8px" }}>
        {q.options.map((opt, i) => (
          <button key={i} onClick={() => pickAnswer(i)} style={{
            background: selected === i ? "rgba(196,146,42,0.1)" : C.surface,
            border:`1px solid ${selected === i ? C.gold : C.border}`,
            borderRadius:"6px", padding:"12px 16px", textAlign:"left",
            cursor:"pointer", fontSize:"13px", color: selected===i ? C.gold : C.text,
            transition:"all 0.12s", ...sans,
          }}>
            <span style={{ color:C.muted, marginRight:"10px", ...mono }}>{String.fromCharCode(65+i)}.</span>{opt}
          </button>
        ))}
      </div>
      <HintControl key={qIdx} gameType="The Brief" hints={hintsForQuestion(q)} />

      <Btn onClick={nextQuestion} disabled={selected === null}>
        {qIdx + 1 < puzzle.questions.length ? "Next Question →" : "Submit Answers →"}
      </Btn>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME: DARK FIBER — Term ↔ Definition matching
// ══════════════════════════════════════════════════════════════════════════════
function GameDarkFiber({ puzzle, streak, onComplete, dailyTotal }) {
  const [selectedTerm, setSelectedTerm] = useState(null);
  const [selectedDef,  setSelectedDef]  = useState(null);
  const [matched,      setMatched]      = useState([]);
  const [wrong,        setWrong]        = useState(false);
  const [scoreVal,     setScoreVal]     = useState(null);
  const [done,         setDone]         = useState(false);
  const [mistakes,     setMistakes]     = useState(0);
  const [shuffledDefs, setShuffledDefs] = useState(() => [...puzzle.pairs].sort(()=>Math.random()-0.5).map(p=>p.term));
  const startTime = useRef(Date.now());

  useEffect(() => {
    if (!selectedTerm || !selectedDef) return;
    if (selectedTerm === selectedDef) {
      const newMatched = [...matched, selectedTerm];
      setMatched(newMatched);
      setSelectedTerm(null);
      setSelectedDef(null);
      if (newMatched.length === puzzle.pairs.length) {
        const elapsed = (Date.now() - startTime.current) / 1000;
        const perfect = mistakes === 0;
        const s = calcScore({ basePoints:puzzle.pairs.length, maxPoints:puzzle.pairs.length, timeElapsed:elapsed, timeLimit:180, perfect, streak });
        setScoreVal(s);
        setDone(true);
      }
    } else {
      setWrong(true);
      setMistakes(m=>m+1);
      setTimeout(() => { setWrong(false); setSelectedTerm(null); setSelectedDef(null); }, 800);
    }
  }, [selectedTerm, selectedDef]);

  if (done) return <ScoreCard score={scoreVal} dailyTotal={(dailyTotal || 0) + scoreVal} puzzleType="Dark Fiber" domain={puzzle.domain} puzzleName={puzzle.name} publicId={puzzle.__publicId}
    streak={streak} onShare={()=>{}} onNext={()=>onComplete(scoreVal, { pairs: puzzle.pairs })}
    isNew7Day={streak===6} />;

  return (
    <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"10px" }}>
      {/* Terms column */}
      <div style={{ display:"flex", flexDirection:"column", gap:"6px" }}>
        <SL color={C.gold}>Terms</SL>
        {puzzle.pairs.map(p => {
          const isMatched = matched.includes(p.term);
          const isSel = selectedTerm === p.term;
          return (
            <button key={p.term} onClick={() => !isMatched && setSelectedTerm(p.term)} style={{
              background: isMatched ? "rgba(74,222,128,0.08)" : isSel ? "rgba(196,146,42,0.12)" : C.surface,
              border:`1px solid ${isMatched ? "rgba(74,222,128,0.3)" : isSel ? C.gold : C.border}`,
              borderRadius:"6px", padding:"10px 12px", textAlign:"left",
              cursor: isMatched ? "default" : "pointer",
              color: isMatched ? C.green : isSel ? C.gold : C.text,
              fontSize:"13px", fontWeight:600, ...mono, transition:"all 0.12s",
            }}>{p.term}</button>
          );
        })}
      </div>
      {/* Definitions column */}
      <div style={{ display:"flex", flexDirection:"column", gap:"6px" }}>
        <SL color={C.cyan||C.sage}>Definitions</SL>
        {shuffledDefs.map(term => {
          const pair = puzzle.pairs.find(p => p.term === term);
          const isMatched = matched.includes(term);
          const isSel = selectedDef === term;
          return (
            <button key={term} onClick={() => !isMatched && setSelectedDef(term)} style={{
              background: isMatched ? "rgba(74,222,128,0.08)" : isSel ? "rgba(140,166,138,0.12)" : C.surface,
              border:`1px solid ${isMatched ? "rgba(74,222,128,0.3)" : isSel ? C.sage : (wrong&&isSel?"rgba(248,113,113,0.4)":C.border)}`,
              borderRadius:"6px", padding:"10px 12px", textAlign:"left",
              cursor: isMatched ? "default" : "pointer",
              color: isMatched ? C.green : isSel ? C.sage : C.text,
              fontSize:"13px", lineHeight:1.5, ...mono, transition:"all 0.12s",
            }}>{pair.def.length > 80 ? pair.def.slice(0,80)+"…" : pair.def}</button>
          );
        })}
      </div>
      {wrong && (
        <div style={{ gridColumn:"1/-1", textAlign:"center", fontSize:"12px", color:C.red,
          background:"rgba(248,113,113,0.06)", border:"1px solid rgba(248,113,113,0.2)",
          borderRadius:"4px", padding:"6px", ...mono }}>
          ✗ Incorrect match — try again ({mistakes} mistakes)
        </div>
      )}
      <div style={{ gridColumn:"1/-1", marginTop:"4px" }}>
        <HintControl gameType="Dark Fiber" hints={hintsForPuzzle("Dark Fiber", puzzle)} />
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME: FREQUENCY — Multiple choice quiz
// ══════════════════════════════════════════════════════════════════════════════
function GameFrequency({ puzzle, streak, onComplete, dailyTotal }) {
  const [qIdx,    setQIdx]    = useState(0);
  const [answers, setAnswers] = useState([]);
  const [selected,setSelected]= useState(null);
  const [revealed,setRevealed]= useState(false);
  const [scoreVal,setScoreVal]= useState(null);
  const [done,    setDone]    = useState(false);
  const startTime = useRef(Date.now());

  function pick(idx) {
    if (revealed) return;
    setSelected(idx);
    setRevealed(true);
  }

  function next() {
    const q = puzzle.questions[qIdx];
    const newAnswers = [...answers, { given:selected, correct:q.correct, ok:selected===q.correct, explanation:q.explanation }];
    setAnswers(newAnswers);
    setSelected(null);
    setRevealed(false);
    if (qIdx + 1 >= puzzle.questions.length) {
      const correct = newAnswers.filter(a=>a.ok).length;
      const elapsed = (Date.now() - startTime.current) / 1000;
      const perfect = correct === puzzle.questions.length;
      const s = calcScore({ basePoints:correct, maxPoints:puzzle.questions.length, timeElapsed:elapsed, timeLimit:240, perfect, streak });
      setScoreVal(s);
      setDone(true);
    } else {
      setQIdx(i=>i+1);
    }
  }

  if (done) return (
    <div style={{ display:"flex", flexDirection:"column", gap:"12px" }}>
      {puzzle.questions.map((q,i) => (
        <div key={i} style={{
          background: answers[i]?.ok ? "rgba(74,222,128,0.05)" : "rgba(248,113,113,0.05)",
          border:`1px solid ${answers[i]?.ok ? "rgba(74,222,128,0.2)" : "rgba(248,113,113,0.2)"}`,
          borderRadius:"8px", padding:"12px" }}>
          <div style={{ fontSize:"13px", color:C.text, marginBottom:"4px", ...sans }}>{q.q}</div>
          <div style={{ fontSize:"12px", color:answers[i]?.ok?C.green:C.red, ...mono }}>
            {answers[i]?.ok ? "✓ Correct" : `✗ Answer: "${q.options[q.correct]}"`}
          </div>
          <div style={{ fontSize:"12px", color:C.muted, marginTop:"4px", lineHeight:1.5, ...mono }}>{q.explanation}</div>
        </div>
      ))}
      <ScoreCard score={scoreVal} dailyTotal={(dailyTotal || 0) + scoreVal} puzzleType="Frequency" domain={puzzle.domain} puzzleName={puzzle.name} publicId={puzzle.__publicId}
        streak={streak} onShare={()=>{}} onNext={()=>onComplete(scoreVal, { answers })}
        isNew7Day={streak===6} />
    </div>
  );

  const q = puzzle.questions[qIdx];
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      <div style={{ display:"flex", justifyContent:"space-between" }}>
        <SL>{qIdx+1} / {puzzle.questions.length}</SL>
        <ProgressBar value={qIdx+1} max={puzzle.questions.length} color={C.violet||C.sage} />
      </div>
      <div style={{ background:C.surface, border:`1px solid ${C.border}`, borderRadius:"10px", padding:"20px" }}>
        <p style={{ fontSize:"16px", color:C.text, margin:0, lineHeight:1.6, ...sans }}>{q.q}</p>
      </div>
      <div style={{ display:"flex", flexDirection:"column", gap:"8px" }}>
        {q.options.map((opt, i) => {
          const isCorrect = revealed && i === q.correct;
          const isWrong   = revealed && i === selected && i !== q.correct;
          return (
            <button key={i} onClick={() => pick(i)} style={{
              background: isCorrect ? "rgba(74,222,128,0.1)" : isWrong ? "rgba(248,113,113,0.1)" :
                (selected===i&&!revealed) ? "rgba(196,146,42,0.1)" : C.surface,
              border:`1px solid ${isCorrect ? "rgba(74,222,128,0.4)" : isWrong ? "rgba(248,113,113,0.4)" :
                (selected===i&&!revealed) ? C.gold : C.border}`,
              borderRadius:"6px", padding:"12px 16px", textAlign:"left",
              cursor: revealed ? "default" : "pointer",
              fontSize:"13px", color: isCorrect ? C.green : isWrong ? C.red :
                (selected===i&&!revealed) ? C.gold : C.text,
              transition:"all 0.15s", ...sans,
            }}>
              <span style={{ color:C.muted, marginRight:"10px", ...mono }}>{String.fromCharCode(65+i)}.</span>{opt}
            </button>
          );
        })}
      </div>
      {!revealed && (
        <HintControl key={qIdx} gameType="Frequency" hints={hintsForQuestion(q)} />
      )}
      {revealed && (
        <div>
          <div style={{ fontSize:"12px", color:C.muted, lineHeight:1.6, ...mono,
            background:"rgba(255,255,255,0.04)", borderRadius:"6px", padding:"10px",
            marginBottom:"10px" }}>{q.explanation}</div>
          <Btn onClick={next}>
            {qIdx + 1 < puzzle.questions.length ? "Next Question →" : "See Results →"}
          </Btn>
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// REPLAY — Already-played-today banner + read-only states per game
// ══════════════════════════════════════════════════════════════════════════════
function ReplayBanner({ gameType, score, onBack }) {
  return (
    <div style={{ background:"rgba(196,146,42,0.1)", border:"1px solid rgba(196,146,42,0.4)",
      borderRadius:"8px", padding:"14px 18px", marginBottom:"20px",
      display:"flex", justifyContent:"space-between", alignItems:"center", flexWrap:"wrap", gap:"10px" }}>
      <div>
        <div style={{ fontSize:"13px", fontWeight:700, color:C.gold, ...sans }}>
          ✓ Already played today
        </div>
        <div style={{ fontSize:"11px", color:C.muted, ...mono, marginTop:"2px" }}>
          You scored {score} pts
        </div>
      </div>
      <button type="button" onClick={onBack} style={{
        background: `rgba(255,255,255,0.04)`,
        border: `1px solid rgba(196,146,42,0.35)`,
        color: C.cream,
        borderRadius: "6px",
        padding: "7px 14px",
        fontSize: "12px",
        fontWeight: 600,
        cursor: "pointer",
        ...sans,
      }}>← Back to Lobby</button>
    </div>
  );
}

function GameRacklReplay({ snapshot, puzzle, score, onBack }) {
  const groups = puzzle?.groups || [];
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      <ReplayBanner gameType="Rackl" score={score} onBack={onBack} />
      {groups.map((g, gi) => (
        <div key={gi} style={{ background:g.color, borderRadius:"8px", padding:"12px 16px",
          display:"flex", alignItems:"center", gap:"12px" }}>
          <span style={{ fontSize:"11px", fontWeight:700, color:g.textColor, letterSpacing:"0.06em", ...mono }}>{g.label}</span>
          <span style={{ fontSize:"11px", color:g.textColor, opacity:0.85, ...mono }}>{g.items.join(" · ")}</span>
        </div>
      ))}
      {snapshot?.mistakes !== undefined && (
        <div style={{ ...mono, fontSize:"11px", color:C.muted }}>
          Mistakes: {snapshot.mistakes}
        </div>
      )}
    </div>
  );
}

function GameSignalDropReplay({ snapshot, puzzle, score, onBack }) {
  // Post-solve reveal. The answer is taken from the snapshot captured when the
  // player finished (live puzzles no longer carry `word`); `puzzle.word` is only
  // a fallback for legacy/mock snapshots.
  const word = normalizeWord(snapshot?.word || puzzle?.word || "");
  const guesses = snapshot?.guesses || [];
  const savedStates = Array.isArray(snapshot?.results) ? snapshot.results : null;
  const cols = word.length || Number(snapshot?.wordLength) || (guesses[0]?.length) || 6;
  const tileColors = { correct:"#1C3424", present:"#5A4010", absent:"#2A2520", empty:"rgba(255,255,255,0.03)" };
  const tileText   = { correct:C.green, present:C.amber, absent:C.muted, empty:C.dim };
  function getTileState(guess, colIdx) {
    const letter = guess[colIdx];
    if (!letter) return "empty";
    if (letter === word[colIdx]) return "correct";
    if (word.includes(letter)) return "present";
    return "absent";
  }
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px", alignItems:"center" }}>
      <ReplayBanner gameType="Signal Drop" score={score} onBack={onBack} />
      <div style={{ display:"flex", flexDirection:"column", gap:"4px" }}>
        {[...Array(6)].map((_, ri) => {
          const guess = guesses[ri] || "";
          const rowStates = savedStates ? savedStates[ri] : null;
          return (
            <div key={ri} style={{ display:"flex", gap:"4px" }}>
              {[...Array(cols)].map((_, ci) => {
                const state = ri < guesses.length
                  ? (rowStates ? (rowStates[ci] || "empty") : getTileState(guess, ci))
                  : "empty";
                return (
                  <div key={ci} style={{
                    width:"44px", height:"44px", borderRadius:"4px",
                    background: tileColors[state] || tileColors.empty,
                    border:`2px solid ${state === "empty" ? C.dim : "transparent"}`,
                    display:"flex", alignItems:"center", justifyContent:"center",
                    fontSize:"16px", fontWeight:700, color: tileText[state] || C.muted,
                    ...mono,
                  }}>{guess[ci] || ""}</div>
                );
              })}
            </div>
          );
        })}
      </div>
      {word && <div style={{ ...mono, fontSize:"13px", color:C.muted }}>The word was {word}</div>}
    </div>
  );
}

function GameStackReplay({ snapshot, puzzle, score, onBack }) {
  const finalOrder = snapshot?.finalOrder || [];
  const correctOrder = snapshot?.correctOrder || puzzle?.correctOrder || [];
  const items = snapshot?.items || puzzle?.items || [];
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      <ReplayBanner gameType="The Stack" score={score} onBack={onBack} />
      {finalOrder.map((itemIdx, rankIdx) => {
        const correctRank = correctOrder.indexOf(itemIdx);
        const isCorrect = correctRank === rankIdx;
        return (
          <div key={itemIdx} style={{
            background: isCorrect ? "rgba(74,222,128,0.08)" : "rgba(248,113,113,0.06)",
            border:`1px solid ${isCorrect ? "rgba(74,222,128,0.3)" : "rgba(248,113,113,0.2)"}`,
            borderRadius:"8px", padding:"12px 16px",
            display:"flex", justifyContent:"space-between", alignItems:"center" }}>
            <div style={{ display:"flex", gap:"12px", alignItems:"center" }}>
              <span style={{ fontSize:"11px", color:isCorrect?C.green:C.red, ...mono }}>#{rankIdx+1}</span>
              <span style={{ fontSize:"13px", color:C.text }}>{items[itemIdx]}</span>
            </div>
            {!isCorrect && <span style={{ fontSize:"11px", color:C.red, ...mono }}>Correct: #{correctRank+1}</span>}
          </div>
        );
      })}
    </div>
  );
}

function GameQAReplay({ answers, questions, score, gameType, onBack }) {
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"12px" }}>
      <ReplayBanner gameType={gameType} score={score} onBack={onBack} />
      {(answers || []).map((a, i) => {
        const q = questions?.[i];
        return (
          <div key={i} style={{
            background: a.ok ? "rgba(74,222,128,0.05)" : "rgba(248,113,113,0.05)",
            border:`1px solid ${a.ok ? "rgba(74,222,128,0.2)" : "rgba(248,113,113,0.2)"}`,
            borderRadius:"8px", padding:"12px 14px" }}>
            <div style={{ fontSize:"13px", color:C.text, marginBottom:"4px", ...sans }}>{a.q || q?.q}</div>
            <div style={{ fontSize:"12px", color:a.ok?C.green:C.red, ...mono }}>
              {a.ok ? "✓ Correct" : "✗ Incorrect"}
            </div>
            {a.explanation && <div style={{ fontSize:"12px", color:C.muted, marginTop:"4px", lineHeight:1.5, ...mono }}>{a.explanation}</div>}
          </div>
        );
      })}
    </div>
  );
}

function GameDarkFiberReplay({ snapshot, puzzle, score, onBack }) {
  const pairs = snapshot?.pairs || puzzle?.pairs || [];
  return (
    <div style={{ display:"flex", flexDirection:"column", gap:"16px" }}>
      <ReplayBanner gameType="Dark Fiber" score={score} onBack={onBack} />
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:"8px" }}>
        {pairs.map(p => (
          <div key={p.term} style={{ display:"contents" }}>
            <div style={{ background:"rgba(74,222,128,0.08)", border:"1px solid rgba(74,222,128,0.3)",
              borderRadius:"6px", padding:"10px 12px", fontSize:"13px", fontWeight:600, color:C.green, ...mono }}>
              {p.term}
            </div>
            <div style={{ background:"rgba(74,222,128,0.08)", border:"1px solid rgba(74,222,128,0.3)",
              borderRadius:"6px", padding:"10px 12px", fontSize:"12px", color:C.green, lineHeight:1.4, ...mono }}>
              {p.def?.length > 80 ? p.def.slice(0,80)+"…" : p.def}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// Render the appropriate read-only replay state for a given game type + snapshot
function GameReplay({ gameType, snapshot, puzzle, onBack }) {
  const score = snapshot?.score || 0;
  if (gameType === "Rackl") return <GameRacklReplay snapshot={snapshot?.puzzleSnapshot} puzzle={puzzle} score={score} onBack={onBack} />;
  if (gameType === "Signal Drop") return <GameSignalDropReplay snapshot={snapshot?.puzzleSnapshot} puzzle={puzzle} score={score} onBack={onBack} />;
  if (gameType === "The Stack") return <GameStackReplay snapshot={snapshot?.puzzleSnapshot} puzzle={puzzle} score={score} onBack={onBack} />;
  if (gameType === "Dark Fiber") return <GameDarkFiberReplay snapshot={snapshot?.puzzleSnapshot} puzzle={puzzle} score={score} onBack={onBack} />;
  // Circuit, The Brief, Frequency — all Q&A style
  const answers = snapshot?.puzzleSnapshot?.answers || [];
  const questions = puzzle?.questions || [];
  return <GameQAReplay answers={answers} questions={questions} score={score} gameType={gameType} onBack={onBack} />;
}

// ── Daily results persistence ────────────────────────────────────────────────
const TODAY = new Date().toISOString().slice(0, 10); // "YYYY-MM-DD"

// ══════════════════════════════════════════════════════════════════════════════
// ACCOUNT PAGE
// ══════════════════════════════════════════════════════════════════════════════
const MAX_ACCOUNT_TEAMS = 5;

function AccountPage({ email, handle, sessionToken, streak, todayScore, seasonScore, dailyResults, onBack, onSignOut, onHandleChange, onSignIn }) {
  const [editHandle, setEditHandle] = useState(handle || "");
  const [handleSaving, setHandleSaving] = useState(false);
  const [handleSaved, setHandleSaved] = useState(false);
  const [handleError, setHandleError] = useState("");

  const [myTeams, setMyTeams] = useState([]); // { team_id, team_name, pending }
  const [myTeamsLoaded, setMyTeamsLoaded] = useState(false);
  const [availableTeams, setAvailableTeams] = useState([]);
  const [teamSearch, setTeamSearch] = useState("");
  const [teamsLoading, setTeamsLoading] = useState(false);
  const [teamSaving, setTeamSaving] = useState(false);
  const [teamError, setTeamError] = useState("");
  const [teamsSaved, setTeamsSaved] = useState(false);

  const [season, setSeason] = useState(null);
  const [showFreeAgencyInfo, setShowFreeAgencyInfo] = useState(false);

  const [showCreateTeam, setShowCreateTeam] = useState(false);
  const [newTeamName, setNewTeamName] = useState("");
  const [createTeamSaving, setCreateTeamSaving] = useState(false);
  const [createTeamError, setCreateTeamError] = useState("");

  const isLocked = season?.locked_at && new Date() > new Date(season.locked_at);
  // Players manage teams (join up to MAX_ACCOUNT_TEAMS, leave) any time unless the
  // season is hard-locked. Joins are immediate — the Free Agency deferral is retired.
  const canEditTeams = sessionToken && !isLocked;
  const atMaxTeams = myTeams.length >= MAX_ACCOUNT_TEAMS;

  useEffect(() => {
    (async () => {
      try {
        const r = await fetch("/api/season/active");
        const d = await r.json();
        setSeason(d.season ?? null);
      } catch {}
    })();
  }, []);

  useEffect(() => {
    if (!sessionToken) return;
    (async () => {
      setTeamsLoading(true);
      try {
        const r = await fetch(`/api/teams?scope=my&token=${encodeURIComponent(sessionToken)}`);
        const d = await r.json();
        setMyTeams(Array.isArray(d.teams) ? d.teams : []);
      } catch {} finally {
        setTeamsLoading(false);
        setMyTeamsLoaded(true);
      }
    })();
  }, [sessionToken]);

  useEffect(() => {
    if (!canEditTeams) return;
    (async () => {
      try {
        const q = teamSearch ? `&q=${encodeURIComponent(teamSearch)}` : "";
        const r = await fetch(`/api/teams?${q}`);
        const d = await r.json();
        setAvailableTeams(Array.isArray(d.teams) ? d.teams : []);
      } catch {}
    })();
  }, [canEditTeams, teamSearch]);

  async function saveHandle() {
    const h = editHandle.trim().toLowerCase();
    if (!/^[a-z0-9_]{3,24}$/.test(h)) { setHandleError("3–24 chars: letters, numbers, underscore"); return; }
    if (!sessionToken) { setHandleError("Sign in to save"); return; }
    setHandleSaving(true); setHandleError("");
    try {
      const r = await fetch("/api/account", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ token: sessionToken, action: "update-handle", newHandle: h }),
      });
      const d = await r.json();
      if (!r.ok) { setHandleError(d.error || "Could not save handle"); return; }
      try { localStorage.setItem(HANDLE_STORAGE_KEY, h); } catch {}
      if (onHandleChange) onHandleChange(h);
      setHandleSaved(true);
      setTimeout(() => setHandleSaved(false), 2500);
    } catch { setHandleError("Network error — try again"); }
    finally { setHandleSaving(false); }
  }

  async function toggleTeam(teamId, teamName) {
    if (!canEditTeams) return;
    const alreadyIn = myTeams.some(t => t.team_id === teamId);
    let next;
    if (alreadyIn) {
      next = myTeams.filter(t => t.team_id !== teamId);
    } else {
      if (myTeams.length >= MAX_ACCOUNT_TEAMS) return;
      next = [...myTeams, { team_id: teamId, team_name: teamName }]; // immediate join
    }
    setMyTeams(next);
    setTeamSaving(true); setTeamError(""); setTeamsSaved(false);
    try {
      const activeSeason = season?.id ?? null;
      const r = await fetch("/api/teams", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ token: sessionToken, team_ids: next.map(t => t.team_id), season_id: activeSeason }),
      });
      const d = await r.json();
      if (!r.ok) { setTeamError(d.error || "Could not update teams"); return; }
      if (Array.isArray(d.teams)) setMyTeams(d.teams);
      setTeamsSaved(true);
      setTimeout(() => setTeamsSaved(false), 2500);
    } catch { setTeamError("Network error — try again"); }
    finally { setTeamSaving(false); }
  }

  async function createTeam() {
    const name = newTeamName.trim();
    if (!name || !canEditTeams || myTeams.length >= MAX_ACCOUNT_TEAMS) return;
    setCreateTeamSaving(true); setCreateTeamError("");
    try {
      const r = await fetch("/api/teams", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "create", token: sessionToken, team_name: name, season_id: season?.id }),
      });
      const d = await r.json();
      if (!r.ok) {
        if (d.error === "team_name_taken") setCreateTeamError("A team with that name already exists — search to join it.");
        else if (d.error === "team_limit_reached") setCreateTeamError("You're already in 5 teams.");
        else setCreateTeamError(d.error || "Could not create team");
        return;
      }
      setMyTeams(prev => [...prev, { team_id: d.team_id, team_name: d.team_name, pending: d.pending }]);
      setShowCreateTeam(false);
      setNewTeamName("");
      setTeamsSaved(true);
      setTimeout(() => setTeamsSaved(false), 2500);
    } catch { setCreateTeamError("Network error — try again"); }
    finally { setCreateTeamSaving(false); }
  }

  const card = {
    background: C.white,
    border: `1px solid rgba(28,52,36,0.12)`,
    borderRadius: "10px",
    padding: "20px 24px",
    marginBottom: "16px",
  };
  const labelStyle = { fontSize:"10px", letterSpacing:"0.12em", color:"rgba(28,52,36,0.5)", textTransform:"uppercase", ...mono, marginBottom:"12px" };
  const inputStyle = {
    flex: "1 1 160px",
    background: C.white,
    border: `1px solid rgba(196,146,42,0.35)`,
    borderRadius: "6px",
    padding: "9px 12px",
    color: C.forest,
    fontSize: "13px",
    ...mono,
  };
  const saveBtn = {
    background: C.gold,
    color: C.forest,
    border: "none",
    borderRadius: "6px",
    padding: "9px 18px",
    fontSize: "12px",
    fontWeight: 700,
    cursor: "pointer",
    letterSpacing: "0.04em",
    whiteSpace: "nowrap",
    ...mono,
  };

  const recentGames = Object.entries(dailyResults || {}).map(([type, r]) => ({ type, score: r.score, date: TODAY }));

  return (
    <div className="ca" style={{ maxWidth:"560px", margin:"0 auto", paddingTop:"32px", paddingBottom:"56px",
      background: C.cream, color: C.forest }}>
      <button type="button" onClick={onBack} style={{ ...mono, fontSize:"11px", color:"rgba(28,52,36,0.55)",
        background:"transparent", border:"none", cursor:"pointer", padding:0,
        marginBottom:"24px", display:"flex", alignItems:"center", gap:"6px" }}>
        ← Back
      </button>
      <div style={{ ...mono, fontSize:"10px", letterSpacing:"0.16em",
        textTransform:"uppercase", color:"rgba(28,52,36,0.5)", marginBottom:"6px" }}>
        Account &amp; Settings
      </div>
      <div style={{ ...sans, fontSize:"24px", fontWeight:700, color:C.forest, marginBottom:"28px" }}>
        {handle ? `@${handle}` : (email ? email.split("@")[0] : "Your Account")}
      </div>

      {/* Sign-in prompt — shown when not authenticated */}
      {!sessionToken && (
        <div style={{ ...card, borderColor:"rgba(196,146,42,0.4)", background:"rgba(196,146,42,0.05)", marginBottom:"20px" }}>
          <div style={labelStyle}>Sign in to unlock</div>
          <p style={{ ...mono, fontSize:"12px", color:"rgba(28,52,36,0.7)", margin:"0 0 14px" }}>
            Sign in to save your handle, join teams, and track your score on the leaderboard.
          </p>
          <button type="button" onClick={onSignIn}
            style={{ ...mono, background:C.gold, color:C.forest, border:"none", borderRadius:"6px",
              padding:"9px 20px", fontSize:"12px", fontWeight:700, cursor:"pointer",
              letterSpacing:"0.04em" }}>
            Sign in →
          </button>
        </div>
      )}

      {/* Stats */}
      <div style={card}>
        <div style={labelStyle}>Stats</div>
        <div style={{ display:"flex", gap:"12px", flexWrap:"wrap" }}>
          {[
            { label:"🔥 Day Streak", value: streak },
            { label:"Today", value: `${todayScore} pts` },
            { label:"Season", value: `${seasonScore} pts` },
          ].map(s => (
            <div key={s.label} style={{ flex:"1 1 100px", border:`1px solid rgba(196,146,42,0.4)`,
              borderRadius:"8px", padding:"12px 14px", textAlign:"center" }}>
              <div style={{ ...sans, fontSize:"20px", fontWeight:700, color:C.gold }}>{s.value}</div>
              <div style={{ ...mono, fontSize:"10px", color:"rgba(28,52,36,0.55)", marginTop:"3px" }}>{s.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Handle */}
      <div style={card}>
        <div style={labelStyle}>Handle</div>
        <div style={{ display:"flex", gap:"8px", alignItems:"center", flexWrap:"wrap" }}>
          <input
            value={editHandle}
            onChange={e => { setEditHandle(e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, "")); setHandleSaved(false); }}
            onKeyDown={e => e.key === "Enter" && saveHandle()}
            placeholder="your_handle"
            maxLength={24}
            autoCapitalize="none" autoCorrect="off" spellCheck={false}
            style={inputStyle}
            disabled={!sessionToken}
          />
          <button type="button" style={{ ...saveBtn, opacity: sessionToken ? 1 : 0.4 }}
            onClick={saveHandle} disabled={handleSaving || !sessionToken}>
            {handleSaving ? "…" : handleSaved ? "Saved ✓" : "Save"}
          </button>
        </div>
        {handleError && <div style={{ ...mono, fontSize:"11px", color:C.red, marginTop:"6px" }}>{handleError}</div>}
        <div style={{ ...mono, fontSize:"11px", color:"rgba(28,52,36,0.45)", marginTop:"6px" }}>
          3–24 chars · letters, numbers, underscore
        </div>
      </div>

      {/* Email — read-only */}
      <div style={card}>
        <div style={labelStyle}>Email</div>
        <div style={{ ...mono, fontSize:"13px", color:C.forest }}>{email || "—"}</div>
        <div style={{ ...mono, fontSize:"11px", color:"rgba(28,52,36,0.45)", marginTop:"4px" }}>
          Email cannot be changed. Sign in with a new email to switch accounts.
        </div>
      </div>

      {/* Teams */}
      <div style={card}>
        {/* Header */}
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:"16px" }}>
          <div style={{ ...labelStyle, marginBottom:0 }}>Teams</div>
          <div style={{ display:"flex", alignItems:"center", gap:"8px" }}>
            <span style={{ ...mono, fontSize:"10px", color:"rgba(28,52,36,0.5)" }}>
              {myTeams.length}/{MAX_ACCOUNT_TEAMS}
            </span>
            {teamsSaved && <span style={{ ...mono, fontSize:"11px", color:C.sage }}>Saved ✓</span>}
          </div>
        </div>

        {/* ── Your teams ── */}
        {teamsLoading ? (
          <div style={{ ...mono, fontSize:"12px", color:"rgba(28,52,36,0.4)", paddingBottom:"12px" }}>Loading…</div>
        ) : !sessionToken ? (
          <div style={{ ...mono, fontSize:"12px", color:"rgba(28,52,36,0.45)", marginBottom:"8px" }}>
            <button type="button" onClick={onSignIn}
              style={{ ...mono, fontSize:"12px", color:C.gold, background:"none", border:"none",
                cursor:"pointer", padding:0, textDecoration:"underline" }}>
              Sign in to join teams →
            </button>
          </div>
        ) : myTeams.length === 0 ? (
          <div style={{ ...mono, fontSize:"12px", color:"rgba(28,52,36,0.4)", paddingBottom:"12px" }}>
            {canEditTeams ? "No teams yet — add one below." : "No teams selected."}
          </div>
        ) : (
          <div style={{ marginBottom: canEditTeams ? "16px" : "4px" }}>
            {myTeams.map((t, i) => (
              <div key={t.team_id}
                style={{ display:"flex", alignItems:"center", justifyContent:"space-between",
                  padding:"10px 0",
                  borderBottom: i < myTeams.length - 1 ? "1px solid rgba(28,52,36,0.07)" : "none" }}>
                <div style={{ display:"flex", alignItems:"center", gap:"8px", flex:1, minWidth:0 }}>
                  <span style={{ ...mono, fontSize:"13px", color:C.forest,
                    overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                    {t.team_name}
                  </span>
                </div>
                {canEditTeams && (
                  <button type="button" onClick={() => toggleTeam(t.team_id, t.team_name)}
                    disabled={teamSaving}
                    style={{ ...mono, fontSize:"18px", color:"rgba(28,52,36,0.3)", background:"none",
                      border:"none", cursor:"pointer", padding:"2px 8px", flexShrink:0, lineHeight:1 }}>×</button>
                )}
              </div>
            ))}
          </div>
        )}

        {/* ── Browse & join — only when editable and myTeams has loaded ── */}
        {canEditTeams && myTeamsLoaded && (
          <>
            {myTeams.length > 0 && (
              <div style={{ borderTop:"1px solid rgba(28,52,36,0.08)", marginBottom:"14px" }} />
            )}

            <input
              value={teamSearch}
              onChange={e => setTeamSearch(e.target.value)}
              placeholder="Search teams…"
              style={{ ...inputStyle, width:"100%", boxSizing:"border-box", marginBottom:"10px" }}
            />

            <div style={{ border:"1px solid rgba(28,52,36,0.1)", borderRadius:"8px",
              maxHeight:"200px", overflowY:"auto", marginBottom:"12px" }}>
              {(() => {
                const joinable = availableTeams.filter(t => !myTeams.some(m => m.team_id === t.id));
                if (joinable.length === 0) {
                  return (
                    <div style={{ ...mono, fontSize:"12px", color:"rgba(28,52,36,0.4)", padding:"14px 16px" }}>
                      {teamSearch ? "No teams match your search." : "No more teams to add."}
                    </div>
                  );
                }
                return joinable.map((t, i) => (
                  <button key={t.id} type="button"
                    onClick={() => toggleTeam(t.id, t.name)}
                    disabled={myTeams.length >= MAX_ACCOUNT_TEAMS || teamSaving}
                    style={{ display:"flex", alignItems:"center", justifyContent:"space-between",
                      width:"100%", padding:"11px 16px", background:"none", border:"none",
                      borderBottom: i < joinable.length - 1 ? "1px solid rgba(28,52,36,0.06)" : "none",
                      textAlign:"left",
                      cursor: myTeams.length >= MAX_ACCOUNT_TEAMS ? "not-allowed" : "pointer",
                      opacity: myTeams.length >= MAX_ACCOUNT_TEAMS ? 0.45 : 1 }}>
                    <span style={{ ...mono, fontSize:"13px", color:C.forest }}>{t.name}</span>
                    <span style={{ ...mono, fontSize:"18px", color:C.forest, opacity:0.4, lineHeight:1 }}>+</span>
                  </button>
                ));
              })()}
            </div>

            {atMaxTeams && (
              <div style={{ ...mono, fontSize:"11px", fontWeight:600, color:C.gold, marginBottom:"12px" }}>
                Max teams reached, leave a team to join a new team.
              </div>
            )}

            {/* Create a new team */}
            {!showCreateTeam ? (
              <button type="button" onClick={() => setShowCreateTeam(true)}
                disabled={myTeams.length >= MAX_ACCOUNT_TEAMS}
                style={{ ...mono, fontSize:"12px", color:C.forest, background:"none",
                  border:`1px solid rgba(28,52,36,0.2)`, borderRadius:"6px",
                  padding:"8px 14px", cursor: myTeams.length >= MAX_ACCOUNT_TEAMS ? "not-allowed" : "pointer",
                  opacity: myTeams.length >= MAX_ACCOUNT_TEAMS ? 0.45 : 1 }}>
                + Create a new team
              </button>
            ) : (
              <div style={{ background:"rgba(28,52,36,0.04)", borderRadius:"8px", padding:"14px" }}>
                <div style={{ ...mono, fontSize:"11px", color:"rgba(28,52,36,0.55)", marginBottom:"8px" }}>
                  New team name
                </div>
                <div style={{ display:"flex", gap:"8px" }}>
                  <input
                    value={newTeamName}
                    onChange={e => { setNewTeamName(e.target.value); setCreateTeamError(""); }}
                    onKeyDown={e => e.key === "Enter" && createTeam()}
                    placeholder="e.g. Deloitte, Team Faraday…"
                    maxLength={80}
                    autoFocus
                    style={{ ...inputStyle, flex:1 }}
                  />
                  <button type="button" onClick={createTeam}
                    disabled={createTeamSaving || !newTeamName.trim()}
                    style={{ ...saveBtn, opacity: (createTeamSaving || !newTeamName.trim()) ? 0.45 : 1 }}>
                    {createTeamSaving ? "…" : "Create"}
                  </button>
                </div>
                {createTeamError && (
                  <div style={{ ...mono, fontSize:"11px", color:C.red, marginTop:"6px" }}>{createTeamError}</div>
                )}
                <button type="button"
                  onClick={() => { setShowCreateTeam(false); setNewTeamName(""); setCreateTeamError(""); }}
                  style={{ ...mono, fontSize:"11px", color:"rgba(28,52,36,0.45)", background:"none",
                    border:"none", cursor:"pointer", padding:0, marginTop:"10px" }}>
                  Cancel
                </button>
              </div>
            )}

            {teamError && (
              <div style={{ ...mono, fontSize:"11px", color:C.red, marginTop:"8px" }}>{teamError}</div>
            )}
          </>
        )}

        {/* Locked status message — only when the season is hard-locked */}
        {isLocked && sessionToken && myTeams.length > 0 && (
          <div style={{ ...mono, fontSize:"11px", color:"rgba(28,52,36,0.45)", marginTop:"4px" }}>
            The season is locked — team changes reopen next season.
          </div>
        )}
      </div>

      {/* Recent Games */}
      {recentGames.length > 0 && (
        <div style={card}>
          <div style={labelStyle}>Recent Games</div>
          <div style={{ display:"flex", flexDirection:"column", gap:"8px" }}>
            {recentGames.map((g, i) => (
              <div key={i} style={{ display:"flex", alignItems:"center", justifyContent:"space-between",
                padding:"8px 0", borderBottom: i < recentGames.length-1 ? `1px solid rgba(28,52,36,0.08)` : "none" }}>
                <span style={{ ...mono, fontSize:"12px", color:C.forest }}>{g.type}</span>
                <div style={{ display:"flex", gap:"16px", alignItems:"center" }}>
                  <span style={{ ...mono, fontSize:"11px", color:"rgba(28,52,36,0.5)" }}>{g.date}</span>
                  <span style={{ ...mono, fontSize:"12px", fontWeight:600, color:C.gold }}>{g.score} pts</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Sign out */}
      {email && (
        <div style={{ marginTop:"8px" }}>
          <button type="button" onClick={onSignOut}
            style={{ ...mono, fontSize:"12px", color:"rgba(28,52,36,0.55)", background:"transparent",
              border:`1px solid rgba(28,52,36,0.2)`, borderRadius:"6px", padding:"9px 18px", cursor:"pointer" }}>
            Sign out
          </button>
        </div>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// SOCIAL GATE — OTP auth (FAR-221)
// Wraps the OTPGate component, passing the in-game brand tokens + Btn.
// ══════════════════════════════════════════════════════════════════════════════
function SocialGate({ trigger, onComplete, onDismiss }) {
  return (
    <OTPGate
      trigger={trigger}
      C={C}
      sans={sans}
      mono={mono}
      Btn={Btn}
      onComplete={onComplete}
      onDismiss={onDismiss}
    />
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME TILES — Lobby
// ══════════════════════════════════════════════════════════════════════════════
// Locked tile order (front-loads quick-momentum games). The neutral `format` chip
// names the mechanic, not a domain — the puzzle bank rotates varied content, so a
// single hardcoded domain ("Power Architecture") on all seven read as a bug.
const GAME_CONFIGS = [
  { type:"Rackl",       desc:"Group the tiles — four connected sets",     time:"~3 min", format:"Connect" },
  { type:"Circuit",     desc:"True/False sprint — beat the clock",         time:"~2 min", format:"Sprint" },
  { type:"Dark Fiber",  desc:"Match terms to their definitions",           time:"~3 min", format:"Match" },
  { type:"Frequency",   desc:"Multiple choice knowledge quiz",             time:"~3 min", format:"Quiz" },
  { type:"The Stack",   desc:"Drag to rank in the correct order",          time:"~2 min", format:"Rank" },
  { type:"Signal Drop", desc:"Guess the industry term — Wordle style",     time:"~2 min", format:"Guess" },
  { type:"The Brief",   desc:"Read the intelligence brief, then answer",   time:"~4 min", format:"Read" },
];

// White card on cream, forest icon tile with the game's neon pictogram, hover
// glow in the game's locked neon. When `played` is true (today's attempt consumed)
// the tile turns forest green with a gold border and a "✓ Played" badge.
function GameTile({ config, onPlay, played, priorScore }) {
  const glow = GAME_NEON[config.type]?.glow || "rgba(196,146,42,.3)";
  return (
    <button type="button" onClick={onPlay} className={played ? undefined : "fdc-game"} style={{
      "--glow": glow,
      position: "relative",
      background: played ? C.forest : C.white,
      border: played ? `1px solid rgba(196,146,42,0.5)` : `1px solid ${C.gray}`,
      borderRadius:"12px",
      padding:"16px", cursor:"pointer", textAlign:"left",
      display:"flex", gap:"16px", alignItems:"center",
      transition:"transform .12s, border-color .12s",
    }}>
      {played && (
        <span style={{
          position:"absolute", top:"8px", right:"10px",
          fontSize:"10px", letterSpacing:"0.08em", color:C.gold,
          background:"rgba(196,146,42,0.15)", border:`1px solid rgba(196,146,42,0.4)`,
          borderRadius:"20px", padding:"2px 8px", ...mono,
        }}>✓ Played</span>
      )}
      <GameIcon game={config.type} size={64} />
      <span style={{ minWidth:0, flex:1 }}>
        <span style={{ display:"block", fontSize:"18px", fontWeight:600, color: played ? C.cream : C.black, ...serif }}>{config.type}</span>
        <span style={{ display:"block", fontSize:"11.5px", color: played ? "rgba(238,230,218,0.7)" : "rgba(20,18,16,0.62)", marginTop:"3px", ...mono }}>{config.desc}</span>
        {played ? (
          <span style={{ display:"inline-block", marginTop:"9px", fontSize:"12px", fontWeight:600, color:C.gold, ...mono }}>
            {priorScore} pts
          </span>
        ) : (
          <span style={{ display:"inline-block", marginTop:"9px", fontSize:"11px", letterSpacing:"0.1em", color:"#4F6B4D", textTransform:"uppercase", border:`1px solid ${C.gray}`, borderRadius:"4px", padding:"1px 7px", ...mono }}>{config.format}</span>
        )}
      </span>
      <span style={{ fontSize:"11px", color: played ? "rgba(238,230,218,0.5)" : "rgba(20,18,16,0.62)", alignSelf:"flex-start", whiteSpace:"nowrap", ...mono }}>{config.time}</span>
    </button>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// GAME SWITCHER — jump to any other game from inside a puzzle
// ══════════════════════════════════════════════════════════════════════════════
// Renders the other six games as their locked homepage neon pictograms (GameIcon).
// Tapping requests a switch; the parent confirms before discarding in-progress play.
function GameSwitcher({ current, onSwitch }) {
  const others = GAME_CONFIGS.filter(c => c.type !== current);
  return (
    <div role="group" aria-label="Switch to another game"
      style={{ display:"flex", alignItems:"center", gap:"8px", flexWrap:"wrap",
        marginTop:"14px", paddingTop:"14px", borderTop:`1px solid ${C.border}` }}>
      <span style={{ fontSize:"11px", color:C.muted, letterSpacing:"0.08em", textTransform:"uppercase", ...mono }}>
        Switch
      </span>
      {others.map(c => (
        <button key={c.type} onClick={() => onSwitch(c.type)} title={c.type}
          aria-label={`Switch to ${c.type}`}
          style={{ background:"transparent", border:"none", padding:0, lineHeight:0,
            cursor:"pointer", borderRadius:"10px" }}>
          <GameIcon game={c.type} size={36} />
        </button>
      ))}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// TEAM LEADERBOARD — teams_v1 standings, wired to per-player Score
// ══════════════════════════════════════════════════════════════════════════════
// Team standings panel. Display numbers come from /api/leaderboard/season
// (team_memberships + score_events — the canonical season scoring source);
// membership actions go through the team-action edge function, whose team_*
// RPCs also write team_memberships (Teams reconciliation, 2026-07-03).
// Signed-in players can start or join a team to put their score on the board.
function TeamLeaderboard({ leaderboard, myTeam, signedIn, busy, error, onCreate, onJoin, onLeave }) {
  const [mode, setMode] = useState(null); // null | "create" | "join"
  const [name, setName] = useState("");
  const [code, setCode] = useState("");
  const [inviteLabel, setInviteLabel] = useState("Invite teammates");
  const rows = Array.isArray(leaderboard) ? leaderboard : [];

  async function handleInvite() {
    if (!myTeam) return;
    setInviteLabel("…");
    const text = `Join my team "${myTeam.name}" on the Faraday Daily Challenge — team code ${myTeam.code}.`;
    const status = await shareViaDevice({ title: "Join my Faraday team", text, url: DC_URL });
    setInviteLabel(status === "Shared" ? "Shared ✓" : status === "Copied" ? "Invite copied ✓" : "Invite teammates");
    if (status !== "idle") setTimeout(() => setInviteLabel("Invite teammates"), 2500);
  }

  const ghostBtn = { ...mono, fontSize:"11px", color:C.forest, background:"transparent",
    border:`1px solid ${C.gray}`, borderRadius:"6px", padding:"7px 12px",
    cursor: busy ? "not-allowed" : "pointer", opacity: busy ? 0.5 : 1, whiteSpace:"nowrap" };
  const input = { ...mono, fontSize:"12px", color:C.black, background:C.cream,
    border:`1px solid ${C.gray}`, borderRadius:"6px", padding:"7px 10px", flex:"1 1 160px", minWidth:"120px" };

  return (
    <section style={{ margin:"28px 0 0", background:C.white, border:`1px solid ${C.gray}`,
      borderRadius:"12px", padding:"20px 22px" }}>
      <div style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", gap:"10px", flexWrap:"wrap" }}>
        <span style={{ ...mono, fontSize:"11px", letterSpacing:"0.14em", color:C.deepAmber, textTransform:"uppercase" }}>
          Team Leaderboard
        </span>
        <span style={{ ...mono, fontSize:"11px", color:"rgba(20,18,16,0.62)" }}>Ranked by Score this season</span>
      </div>

      {rows.length === 0 ? (
        <div style={{ ...mono, fontSize:"12px", color:"rgba(20,18,16,0.62)", marginTop:"14px" }}>
          No teams yet — be the first to start one.
        </div>
      ) : (
        <div style={{ marginTop:"14px", display:"flex", flexDirection:"column", gap:"4px" }}>
          {rows.map(t => {
            const mine = myTeam && t.team_id === myTeam.team_id;
            return (
              <div key={t.team_id} style={{ display:"flex", alignItems:"center", gap:"10px",
                padding:"8px 10px", borderRadius:"6px",
                background: mine ? "rgba(196,146,42,0.12)" : "transparent",
                border:`1px solid ${mine ? "rgba(196,146,42,0.4)" : "transparent"}` }}>
                <span style={{ ...mono, fontSize:"12px", color:C.deepAmber, width:"26px" }}>#{t.rank}</span>
                <span style={{ ...sans, fontSize:"13px", fontWeight:600, color:C.black, flex:1, minWidth:0,
                  overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{t.name}</span>
                <span style={{ ...mono, fontSize:"11px", color:"rgba(20,18,16,0.62)" }}>{t.members} member{t.members === 1 ? "" : "s"}</span>
                <span style={{ ...mono, fontSize:"11px", color:"rgba(20,18,16,0.62)", width:"54px", textAlign:"right" }}>{(t.today || 0).toLocaleString()} today</span>
                <span style={{ ...mono, fontSize:"12px", fontWeight:600, color:C.forest, width:"66px", textAlign:"right" }}>{(t.season || 0).toLocaleString()}</span>
              </div>
            );
          })}
        </div>
      )}

      <div style={{ marginTop:"16px", borderTop:`1px solid ${C.gray}`, paddingTop:"14px" }}>
        {!signedIn ? (
          <div style={{ ...mono, fontSize:"12px", color:"rgba(20,18,16,0.62)" }}>
            Sign in to start or join a team and put your score on the board.
          </div>
        ) : myTeam ? (
          <div style={{ display:"flex", alignItems:"center", gap:"10px", flexWrap:"wrap" }}>
            <span style={{ ...mono, fontSize:"11px", color:C.forest }}>
              On <b>{myTeam.name}</b> · code <b>{myTeam.code}</b>
            </span>
            <button onClick={handleInvite} disabled={busy} style={ghostBtn}>{inviteLabel}</button>
            <button onClick={onLeave} disabled={busy} style={ghostBtn}>Leave team</button>
          </div>
        ) : mode === null ? (
          <div style={{ display:"flex", gap:"8px", flexWrap:"wrap" }}>
            <button onClick={() => setMode("create")} disabled={busy} style={ghostBtn}>Start a team</button>
            <button onClick={() => setMode("join")} disabled={busy} style={ghostBtn}>Join with code</button>
          </div>
        ) : mode === "create" ? (
          <div style={{ display:"flex", gap:"8px", flexWrap:"wrap" }}>
            <input value={name} onChange={e => setName(e.target.value)} placeholder="Team name" style={input}
              onKeyDown={e => e.key === "Enter" && name.trim() && onCreate(name.trim())} />
            <button onClick={() => name.trim() && onCreate(name.trim())} disabled={busy || !name.trim()} style={ghostBtn}>
              {busy ? "…" : "Create"}
            </button>
            <button onClick={() => { setMode(null); setName(""); }} disabled={busy} style={ghostBtn}>Cancel</button>
          </div>
        ) : (
          <div style={{ display:"flex", gap:"8px", flexWrap:"wrap" }}>
            <input value={code} onChange={e => setCode(e.target.value)} placeholder="Team code" style={input}
              onKeyDown={e => e.key === "Enter" && code.trim() && onJoin(code.trim())} />
            <button onClick={() => code.trim() && onJoin(code.trim())} disabled={busy || !code.trim()} style={ghostBtn}>
              {busy ? "…" : "Join"}
            </button>
            <button onClick={() => { setMode(null); setCode(""); }} disabled={busy} style={ghostBtn}>Cancel</button>
          </div>
        )}
        {error && <div style={{ ...mono, fontSize:"12px", color:C.red, marginTop:"8px" }}>{error}</div>}
      </div>
    </section>
  );
}

// ── First-visit splash ────────────────────────────────────────────────────────
// One-time, full-screen cream welcome shown on a player's first visit. Dismissed
// by the single "Enter →" CTA, which persists faraday_splash_seen so it never
// returns. Rendered as a fixed overlay above the whole app (see DailyChallenge).
const SPLASH_SEEN_KEY = "faraday_splash_seen";

function SplashScreen({ onEnter }) {
  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label="Welcome to Faraday's Daily Challenge"
      style={{
        position: "fixed", inset: 0, zIndex: 1000,
        background: C.cream, color: C.black,
        display: "flex", flexDirection: "column", alignItems: "center",
        justifyContent: "center", padding: "32px 24px",
        overflowY: "auto", ...sans,
      }}
    >
      {/* thin gold rule top & bottom to echo the masthead lockup */}
      <div style={{ position:"absolute", top:0, left:0, right:0, height:"3px", background:C.gold }} />
      <div style={{ position:"absolute", bottom:0, left:0, right:0, height:"3px", background:C.gold }} />

      <div style={{ maxWidth:"520px", width:"100%", textAlign:"center",
        display:"flex", flexDirection:"column", alignItems:"center", gap:"22px" }}>

        {/* Faraday F logo + wordmark */}
        <BrandMark size={44} framed />
        <div style={{ lineHeight:1.2 }}>
          <div style={{ ...serif, fontWeight:700, fontSize:"clamp(24px,5vw,34px)",
            letterSpacing:"0.02em", color:C.black }}>Faraday</div>
          <div style={{ ...mono, fontSize:"12px", letterSpacing:"0.22em",
            color:C.gold, marginTop:"6px" }}>DAILY CHALLENGE</div>
        </div>

        <div className="double-rule" aria-hidden="true" style={{ width:"56px" }} />

        {/* Welcome copy (exact, brand-approved) */}
        <p style={{ fontSize:"15px", lineHeight:1.65, color:"rgba(20,18,16,0.78)",
          maxWidth:"46ch", margin:0 }}>
          Faraday is your unfair advantage in an uncertain market. It is an
          intelligence service that ingests and scans thousands of data sources
          each day and provides insights into the signals and threads without the
          noise and clutter. This intelligence has been distilled into a set of
          challenges accessible as competitive and familiar games.
        </p>
        <p style={{ ...serif, fontSize:"18px", lineHeight:1.5, color:C.black,
          fontWeight:600, margin:0 }}>
          Welcome to Faraday&rsquo;s Daily Challenge! Good Luck!
        </p>

        {/* Single CTA — sets faraday_splash_seen and dismisses */}
        <button
          type="button"
          onClick={onEnter}
          autoFocus
          style={{
            marginTop:"6px",
            background: C.forest,
            border: `1px solid ${C.gold}`,
            color: C.cream,
            borderRadius: "8px",
            padding: "13px 38px",
            fontSize: "14px",
            fontWeight: 700,
            letterSpacing: "0.1em",
            cursor: "pointer",
            transition: "all 0.15s",
            boxShadow: "0 2px 14px rgba(28,52,36,0.18)",
            ...mono,
          }}
        >
          ENTER →
        </button>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// HEADER ICON-DROPDOWN NAV (feature/header-icon-nav)
// ══════════════════════════════════════════════════════════════════════════════
// Five right-aligned icon triggers (All Games · Help & Feedback · Compete ·
// Account · More Faraday), each opening a click-toggle dropdown. Single-open-at-
// a-time; click-outside / Escape close; caret flips when open. Icons are inline
// SVG (stroke 1.8, no fills, no icon library). Styling lives in the injected
// <style> block (`.dc-*` classes).

// Inline SVGs for the five triggers — grid · help · trophy · gear · hamburger.
function NavGlyph({ name }) {
  const common = { viewBox: "0 0 24 24", strokeWidth: 1.8, strokeLinecap: "round", strokeLinejoin: "round" };
  if (name === "grid") return (
    <svg {...common}><rect x="3" y="3" width="7" height="7" rx="1.5"/><rect x="14" y="3" width="7" height="7" rx="1.5"/><rect x="3" y="14" width="7" height="7" rx="1.5"/><rect x="14" y="14" width="7" height="7" rx="1.5"/></svg>
  );
  if (name === "help") return (
    <svg {...common}><circle cx="12" cy="12" r="10"/><path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3"/><path d="M12 17h.01"/></svg>
  );
  if (name === "trophy") return (
    <svg {...common}><path d="M8 21h8M12 17v4M7 4h10v5a5 5 0 0 1-10 0V4z"/><path d="M7 6H4a2 2 0 0 0 2 4M17 6h3a2 2 0 0 1-2 4"/></svg>
  );
  if (name === "gear") return (
    <svg {...common}><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 1 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 1 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 1 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 1 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 1 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.6a1.65 1.65 0 0 0 1-1.51V3a2 2 0 1 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 1 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 1 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>
  );
  return ( // hamburger
    <svg {...common}><path d="M3 6h18M3 12h18M3 18h18"/></svg>
  );
}

// ── EDIT MENU TEXT + LINKS HERE ───────────────────────────────────────────────
// Single source of truth for every header dropdown. To change a label, add/remove
// an item, or repoint a link, edit this function only. Each item is one of:
//   { label, onClick }   → runs a handler (in-app navigation / auth / sign-out)
//   { label, href }      → navigates to a URL (same tab)
//   { label, current:true } → styled as the active destination
//   { label, disabled:true } → grayed out, not clickable (reserved for later)
//   { divider:true }     → a horizontal rule
//   { heading:"…" }      → a small uppercase group label (like the menu title)
// The Account menu is auth-conditional (see the `email` branch).
// Mirrors buildSiteMenus in SiteHeaderNav.tsx — keep the two in sync.
function buildHeaderMenus({ email, activeGame, onGame, onSignIn, onAccount, onSettings, onSignOut }) {
  return [
    // All 7 games, in lobby-grid order (GAME_CONFIGS is the source of truth).
    { id: "games", icon: "grid", label: "All Games", items:
      GAME_CONFIGS.map(c => ({ label: c.type, onClick: () => onGame(c.type), current: c.type === activeGame })),
    },
    { id: "help", icon: "help", label: "Help & Feedback", items: [
      // Evergreen "Hints" (general how-to-play help) stays as-is — the
      // day-scoped "Hints Today" below is a distinct page (FAR-287).
      // Glossary / Report a Bug / Feedback moved to the gear (Account) menu.
      { label: "Hints",           href: "/help/hints" },
      { label: "Tips and Tricks", href: "/help/tips" },
      { label: "Questions",       href: "/help/questions" },
      { divider: true },
      { heading: "Today's Challenge" },
      { label: "Hints Today",             href: "/challenge/hints" },
      { label: "About Today's Challenge", href: "/challenge/about" },
      { label: "Answers Today",           href: "/challenge/answers" },
    ]},
    { id: "compete", icon: "trophy", label: "Compete", items: [
      { label: "Leaderboard — Today",  href: "/leaderboard" },  // TODO: no today-only view yet → season board (shows a Today column)
      { label: "Leaderboard — Season", href: "/leaderboard" },
      { label: "Teams",                href: "/leaderboard?view=teams" },
      { label: "Free Agency",          href: "/free-agency" },
    ]},
    { id: "account", icon: "gear", label: "Account", items: email ? [
      { label: "Account",  onClick: onAccount },
      { label: "Settings", onClick: onSettings },  // same Account screen today — no separate settings page yet
      { label: "Notifications", href: "/account/notifications" },
      { divider: true },
      // Moved here from the "?" Help menu (Myke, 2026-07-03).
      { label: "Glossary",     href: "/help/glossary" },
      { label: "Report a Bug", href: "/help/report-a-bug" },
      { label: "Feedback",     href: "/help/feedback" },
      { divider: true },
      { label: "Sign Out", onClick: onSignOut },
    ] : [
      { label: "Sign In", onClick: onSignIn },
      { divider: true },
      { label: "Glossary",     href: "/help/glossary" },
      { label: "Report a Bug", href: "/help/report-a-bug" },
      { label: "Feedback",     href: "/help/feedback" },
    ]},
    { id: "menu", icon: "hamburger", label: "More Faraday", items: [
      { label: "About Faraday Intelligence", href: "/about" },
      { label: "Who is Faraday",             href: "/who-is-faraday" },
      { label: "Share / Invite",             href: "/share" },
      { label: "Notifications",              href: "/account/notifications" },
      { label: "Faraday Merchandise",        href: "/merch" },
      { label: "Faraday Academy",            disabled: true },  // reserved for a later phase — no link by design
      { divider: true },
      { label: "Terms / Privacy",            href: "/legal" },
    ]},
  ];
}

function HeaderIconNav({ menus }) {
  const [open, setOpen] = useState(null); // menu id currently open, or null
  const wrapRef = useRef(null);

  useEffect(() => {
    if (!open) return;
    const onDocClick = (e) => { if (wrapRef.current && !wrapRef.current.contains(e.target)) setOpen(null); };
    const onKey = (e) => { if (e.key === "Escape") setOpen(null); };
    document.addEventListener("click", onDocClick);
    document.addEventListener("keydown", onKey);
    return () => { document.removeEventListener("click", onDocClick); document.removeEventListener("keydown", onKey); };
  }, [open]);

  function activate(item) {
    setOpen(null);
    if (typeof item.onClick === "function") item.onClick();
    else if (item.href) window.location.href = item.href;
  }

  return (
    <div ref={wrapRef} style={{ display: "flex", alignItems: "center", gap: "19px" }}>
      {menus.map((m) => {
        const isOpen = open === m.id;
        return (
          <div key={m.id} className={`dc-navwrap${isOpen ? " open" : ""}`}>
            <button
              type="button"
              className="dc-trigger"
              aria-haspopup="menu"
              aria-expanded={isOpen}
              aria-label={m.label}
              title={m.label}
              onClick={(e) => { e.stopPropagation(); setOpen(isOpen ? null : m.id); }}
            >
              <NavGlyph name={m.icon} />
              <span className="dc-caret" aria-hidden="true" />
            </button>
            <div className="dc-dd" role="menu" aria-label={m.label}>
              <div className="dc-dd-label">{m.label}</div>
              {m.items.map((it, i) =>
                it.divider ? (
                  <hr key={i} />
                ) : it.heading ? (
                  <div key={i} className="dc-dd-label">{it.heading}</div>
                ) : (
                  <button
                    key={i}
                    type="button"
                    role="menuitem"
                    className={`dc-dd-item${it.current ? " current" : ""}${it.disabled ? " disabled" : ""}`}
                    disabled={!!it.disabled}
                    aria-disabled={it.disabled || undefined}
                    title={it.disabled ? "Coming soon" : undefined}
                    onClick={() => { if (!it.disabled) activate(it); }}
                  >
                    {it.label}{it.current ? " ·" : ""}
                  </button>
                )
              )}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════════════════
// MAIN — Daily Challenge App
// ══════════════════════════════════════════════════════════════════════════════
export default function DailyChallenge() {
  const navIconsLabelHidden = useWindowWidth() <= 430;  // FAR-207: icon-only on mobile
  const [screen,     setScreen]     = useState("lobby");  // lobby | game | gate | account
  const [activeGame, setActiveGame] = useState(null);
  const [email,      setEmail]      = useState(null);     // registered email
  const [handle,     setHandle]     = useState(null);     // canonical leaderboard handle (mirrored from /auth)
  const [optedOut,   setOptedOut]   = useState(false);    // soft opt-out mirror ("leave the game")
  const [prevScreen, setPrevScreen] = useState("lobby");
  const [pendingSwitch, setPendingSwitch] = useState(null); // game-switcher confirm (discard in-progress puzzle)
  // Session counters — honest defaults for an anonymous session (0). These
  // increment as the player completes games in-session. Cross-session streak
  // persistence belongs to the subscriber session (Supabase) and is wired
  // separately; we never seed these with fabricated values. (FAR-63 stats AC.)
  const [streak,     setStreak]     = useState(0);
  const [gamesPlayed,setGamesPlayed]= useState(0);
  const [gateReason, setGateReason] = useState(null);
  const [lastScore,  setLastScore]  = useState(null);
  // First-visit welcome splash. Initialised false so SSR/first paint match
  // (no hydration mismatch); the mount effect flips it on only when the
  // faraday_splash_seen flag is absent. Dismiss persists the flag for good.
  const [showSplash, setShowSplash] = useState(false);

  // One-play-per-day local results: { [gameType]: { score, completedAt, puzzleSnapshot } }
  const [dailyResults, setDailyResults] = useState(() => {
    try {
      const stored = localStorage.getItem(`faraday_daily_${TODAY}`);
      return stored ? JSON.parse(stored) : {};
    } catch { return {}; }
  });

  function recordResult(gameType, score, puzzleSnapshot) {
    setDailyResults(prev => {
      if (prev[gameType]) return prev; // never overwrite an existing entry
      const updated = { ...prev, [gameType]: { score, completedAt: Date.now(), puzzleSnapshot } };
      try { localStorage.setItem(`faraday_daily_${TODAY}`, JSON.stringify(updated)); } catch {}
      return updated;
    });
  }

  // todayScore derived reactively from dailyResults (local fallback for guests)
  const todayScore = Object.values(dailyResults).reduce((s, r) => s + (r.score || 0), 0);
  // Authoritative Today + Season totals for signed-in players, sourced from
  // /api/leaderboard/season (`you.today_points` / `you.total_points`) — the same
  // score_events source the /leaderboard page uses. Previously `seasonScore` was
  // just a copy of todayScore, so the header/Account showed Season == Today.
  const [serverToday,  setServerToday]  = useState(null);
  const [serverSeason, setServerSeason] = useState(null);
  // Verified subscriber session (set by /auth after a magic link). When
  // present, streak/completions are hydrated from and persisted to
  // Supabase — the masthead chips and stat line show real results.
  const [sessionToken,     setSessionToken]     = useState(null);
  const [todayCompletions, setTodayCompletions] = useState({});
  const [lastDailyTotal,   setLastDailyTotal]   = useState(0);
  // Team leaderboard (teams_v1) wired to per-player Score: public standings, plus
  // the caller's team when signed in. Refreshed after each completion.
  const [leaderboard, setLeaderboard] = useState([]);
  const [myTeam,      setMyTeam]      = useState(null);
  const [teamBusy,    setTeamBusy]    = useState(false);
  const [teamError,   setTeamError]   = useState("");

  // Live puzzles + tip from the Airtable Puzzle Bank (via /api/challenge/today).
  // Each falls back to built-in mock data if the fetch fails or a type is absent,
  // so the lobby always renders all 7 games even if Airtable is unreachable.
  const [livePuzzles,  setLivePuzzles]  = useState({});
  const [tipOfTheDay,  setTipOfTheDay]  = useState(null);

  // Show the welcome splash once per browser. Runs on mount only, so it is
  // SSR-safe (localStorage is never touched during render).
  useEffect(() => {
    try {
      if (!localStorage.getItem(SPLASH_SEEN_KEY)) setShowSplash(true);
    } catch { /* storage disabled — skip the splash silently */ }
  }, []);

  function dismissSplash() {
    try { localStorage.setItem(SPLASH_SEEN_KEY, "1"); } catch { /* ignore */ }
    setShowSplash(false);
  }

  useEffect(() => {
    let cancelled = false;
    fetch("/api/challenge/today")
      .then(r => r.ok ? r.json() : Promise.reject(new Error(`HTTP ${r.status}`)))
      .then(data => {
        if (cancelled || !data) return;
        if (data.puzzles && typeof data.puzzles === "object") setLivePuzzles(data.puzzles);
        if (data.tip) setTipOfTheDay(data.tip);
      })
      .catch(() => { /* keep mock fallback */ });
    return () => { cancelled = true; };
  }, []);

  // Hydrate the subscriber's real state (play streak, today's
  // completions) from Supabase when a verified session exists in storage.
  useEffect(() => {
    let token = null;
    try { token = localStorage.getItem(SESSION_STORAGE_KEY); } catch { /* storage disabled */ }
    if (!token) return;

    let cancelled = false;
    fetch(`/api/subscriber-state?token=${encodeURIComponent(token)}`)
      .then(r => r.json().then(data => ({ ok: r.ok, status: r.status, data })))
      .then(({ ok, status, data }) => {
        if (cancelled) return;
        if (!ok) {
          if (status === 401) {
            try {
              localStorage.removeItem(SESSION_STORAGE_KEY);
              localStorage.removeItem(EMAIL_STORAGE_KEY);
            } catch { /* ignore */ }
          }
          return;
        }
        setSessionToken(token);
        setEmail(data.email);
        if (data.handle) {
          setHandle(data.handle);
          try { localStorage.setItem(HANDLE_STORAGE_KEY, data.handle); } catch { /* ignore */ }
        }
        setStreak(data.playStreak || 0);
        setTodayCompletions(data.todayCompletions || {});
        setGamesPlayed(Object.keys(data.todayCompletions || {}).length);
        // Seed the running daily total from today's already-played games (FAR-207).
        const seedTotal = Object.values(data.todayCompletions || {})
          .reduce((sum, c) => sum + (c.score || 0), 0);
        if (seedTotal > 0) setLastDailyTotal(seedTotal);
        if (data.active === false) {
          setOptedOut(true);
          try { localStorage.setItem(OPTED_OUT_STORAGE_KEY, "1"); } catch { /* ignore */ }
        }
      })
      .catch(() => { /* offline — keep anonymous session counters */ });
    return () => { cancelled = true; };
  }, []);

  // Team standings — public board, plus the caller's team/rank when a session
  // token is present. Non-critical: failures leave the panel empty silently.
  const refreshLeaderboard = useCallback(() => {
    let token = null;
    try { token = localStorage.getItem(SESSION_STORAGE_KEY); } catch { /* storage disabled */ }

    // Standings come from the SAME season-scoring source as /leaderboard
    // (score_events, non-pending members) so the team totals actually reflect
    // the sum of each team's members' scores. (The old MW-era team_leaderboard
    // RPC has since been rewritten over the same sources — Teams reconciliation
    // 2026-07-03 — but this route stays the display source of truth.)
    const tq = token ? `?token=${encodeURIComponent(token)}` : "";
    const standingsP = fetch(`/api/leaderboard/season${tq}`)
      .then(r => (r.ok ? r.json() : null))
      .then(data => {
        if (!data || !Array.isArray(data.leaderboard)) return;
        // Authoritative Today + Season totals for the signed-in player.
        if (data.you) {
          setServerToday(typeof data.you.today_points === "number" ? data.you.today_points : null);
          setServerSeason(typeof data.you.total_points === "number" ? data.you.total_points : null);
        }
        const byTeam = new Map();
        for (const row of data.leaderboard) {
          for (const tm of (row.teams || [])) {
            let e = byTeam.get(tm.team_id);
            if (!e) { e = { team_id: tm.team_id, name: tm.team_name, season: 0, today: 0, members: new Set() }; byTeam.set(tm.team_id, e); }
            e.season += row.total_points || 0;
            e.today  += row.today_points || 0;
            e.members.add(row.subscriber_id);
          }
        }
        const standings = [...byTeam.values()]
          .map(e => ({ team_id: e.team_id, name: e.name, season: e.season, today: e.today, members: e.members.size }))
          .sort((a, b) => b.season - a.season || b.members - a.members || a.name.localeCompare(b.name))
          .map((e, i) => ({ ...e, rank: i + 1 }));
        setLeaderboard(standings);
      })
      .catch(() => { /* leaderboard is non-critical */ });

    // The caller's own membership (team name + code for Invite/Leave) still comes
    // from the membership edge function — display numbers are sourced above.
    const qs = new URLSearchParams({ limit: "10" });
    if (token) qs.set("token", token);
    const myP = fetch(`${EDGE_FUNCTIONS_BASE}/get-team-leaderboard?${qs.toString()}`)
      .then(r => (r.ok ? r.json() : null))
      .then(data => { if (data) setMyTeam(data.myTeam || null); })
      .catch(() => { /* non-critical */ });

    return Promise.all([standingsP, myP]);
  }, []);

  useEffect(() => { refreshLeaderboard(); }, [refreshLeaderboard]);

  // Team membership actions (create/join/leave) — session-gated via team-action.
  function teamAction(action, payload) {
    let token = null;
    try { token = localStorage.getItem(SESSION_STORAGE_KEY); } catch { /* storage disabled */ }
    if (!token) { setTeamError("Sign in first"); return; }
    setTeamBusy(true);
    setTeamError("");
    fetch(`${EDGE_FUNCTIONS_BASE}/team-action`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ sessionToken: token, action, ...payload }),
    })
      .then(r => r.json().then(data => ({ ok: r.ok, data })))
      .then(({ ok, data }) => {
        if (!ok) { setTeamError(data?.error || "Team action failed"); return; }
        setMyTeam(data.myTeam || null);
        refreshLeaderboard();
      })
      .catch(() => setTeamError("Network error — try again"))
      .finally(() => setTeamBusy(false));
  }

  useEffect(() => {
    const link = document.createElement("link");
    link.rel  = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=IBM+Plex+Mono:wght@300;400;500&family=IBM+Plex+Serif:ital,wght@0,400;0,700;1,400&family=Bricolage+Grotesque:wght@400;500;600;700&display=swap";
    document.head.appendChild(link);
    const style = document.createElement("style");
    style.textContent = `
      * { box-sizing:border-box; }
      @keyframes fadeUp { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }
      .ca { animation:fadeUp 0.3s ease forwards; }
      button { font-family:inherit; }
      input { font-family:inherit; }
      input:focus { border-color:rgba(196,146,42,0.4)!important; outline:none; box-shadow:0 0 0 2px rgba(196,146,42,0.05); }
      a:focus-visible, button:focus-visible { outline:2px solid #C4922A; outline-offset:3px; }
      /* Game tile hover — lift + neon glow in the game's locked color */
      .fdc-game:hover { transform:translateY(-2px); border-color:#1C3424 !important; }
      .fdc-game:hover .icon-tile { box-shadow:0 0 18px var(--glow); }
      /* Mobile nav collapse (FAR-207): label visibility is controlled in JS via
         useWindowWidth (≤430px → icon only), so no CSS override is needed here. */

      /* ── Header icon-dropdown nav (feature/header-icon-nav) ─────────────── */
      .dc-navwrap { position:relative; display:flex; flex-direction:column; align-items:center; }
      .dc-trigger { display:flex; flex-direction:column; align-items:center; gap:5px;
        background:none; border:none; cursor:pointer; padding:4px 2px; -webkit-tap-highlight-color:transparent; }
      .dc-trigger svg { width:19px; height:19px; stroke:rgba(238,230,218,0.62); fill:none; transition:stroke .12s; }
      .dc-navwrap.open .dc-trigger svg, .dc-trigger:hover svg { stroke:${C.gold}; }
      .dc-caret { width:6px; height:6px; border-right:1.4px solid rgba(238,230,218,0.35);
        border-bottom:1.4px solid rgba(238,230,218,0.35); transform:rotate(45deg); margin-top:-1px;
        transition:transform .15s, border-color .15s; }
      .dc-navwrap.open .dc-caret { transform:rotate(-135deg); border-color:${C.gold}; }
      .dc-dd { position:absolute; top:calc(100% + 12px); right:-8px; text-align:left;
        background:${C.forest}; border:1px solid rgba(196,146,42,0.35); border-radius:8px;
        min-width:174px; padding:6px; box-shadow:0 12px 28px rgba(20,18,16,0.4);
        opacity:0; visibility:hidden; transform:translateY(-4px);
        transition:opacity .15s ease, transform .15s ease; z-index:60; }
      .dc-navwrap.open .dc-dd { opacity:1; visibility:visible; transform:translateY(0); }
      .dc-dd-label { font-family:'IBM Plex Mono',monospace; font-size:8.5px; letter-spacing:0.12em;
        color:rgba(238,230,218,0.4); text-transform:uppercase; padding:6px 10px 4px; }
      .dc-dd-item { display:block; width:100%; text-align:left; font-family:'IBM Plex Mono',monospace;
        font-size:11px; color:${C.cream}; text-decoration:none; padding:8px 10px; border-radius:5px;
        background:none; border:none; cursor:pointer; }
      .dc-dd-item:hover, .dc-dd-item:focus-visible { background:rgba(196,146,42,0.15); color:${C.gold}; }
      .dc-dd-item.current { color:${C.gold}; }
      .dc-dd-item.disabled, .dc-dd-item.disabled:hover { background:none; color:rgba(238,230,218,0.32); cursor:default; }
      .dc-dd hr { border:none; border-top:1px solid rgba(238,230,218,0.1); margin:4px 6px; }
      @media (prefers-reduced-motion: reduce){
        .dc-dd, .dc-caret, .dc-trigger svg { transition:none; }
      }
    `;
    document.head.appendChild(style);
  }, []);

  // Hydrate the canonical handle + soft opt-out mirror from local storage. Both
  // are client-side mirrors (no backend round-trip) — see lib/supabase.ts.
  useEffect(() => {
    try {
      const h = localStorage.getItem(HANDLE_STORAGE_KEY);
      if (h) setHandle(h);
      setOptedOut(localStorage.getItem(OPTED_OUT_STORAGE_KEY) === "1");
    } catch { /* storage disabled */ }
  }, []);

  // Game switcher: switching mid-puzzle discards in-progress state, so confirm
  // first. Entering any game screen counts as in-progress.
  function requestSwitch(type) { setPendingSwitch(type); }
  function confirmSwitch() {
    if (!pendingSwitch) return;
    const t = pendingSwitch;
    setPendingSwitch(null);
    startGame(t);
  }

  function startGame(gameType) {
    setActiveGame(gameType);
    setScreen("game");
  }

  function openAccount() {
    setPrevScreen(screen);
    setScreen("account");
    refreshLeaderboard();  // refresh authoritative Today/Season totals for the STATS card
  }

  function handleSignOut() {
    try {
      localStorage.removeItem(SESSION_STORAGE_KEY);
      localStorage.removeItem(EMAIL_STORAGE_KEY);
      localStorage.removeItem(HANDLE_STORAGE_KEY);
      localStorage.removeItem(OPTED_OUT_STORAGE_KEY);
    } catch { /* ignore */ }
    setEmail(null);
    setHandle(null);
    setSessionToken(null);
    setStreak(0);
    setDailyResults({});
    setOptedOut(false);
    setScreen("lobby");
  }

  // Deep-link: /daily-challenge?game=<type> opens that puzzle directly (from the
  // homepage neon icons) instead of landing on the lobby. Runs once on mount.
  useEffect(() => {
    let g = null;
    try { g = new URLSearchParams(window.location.search).get("game"); } catch { /* no search */ }
    if (!g) return;
    const match = GAME_CONFIGS.find(c => c.type.toLowerCase() === g.toLowerCase());
    if (match) startGame(match.type);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  function onGameComplete(score, puzzleSnapshot, result) {
    const playedGame = activeGame;
    setLastScore(score);
    // Record locally for one-play enforcement + replay state
    if (playedGame) recordResult(playedGame, score, puzzleSnapshot);
    // Soft opt-out: no streak accrual, no server persistence.
    if (optedOut) { setScreen("lobby"); return; }
    setGamesPlayed(g => g+1);
    setStreak(s => s+1);
    if (sessionToken && playedGame) {
      // Optimistic update: mark this game completed locally.
      const updatedCompletions = {
        ...todayCompletions,
        [playedGame]: { score, completedAt: new Date().toISOString() },
      };
      setTodayCompletions(updatedCompletions);
      // Compute optimistic running daily total for win screen.
      const optimisticTotal = Object.values(updatedCompletions).reduce(
        (sum, c) => sum + (c.score || 0), 0
      );
      setLastDailyTotal(optimisticTotal);
    } else {
      // Anonymous session: accumulate session-local daily total (no server write).
      setLastDailyTotal(t => t + score);
    }
    if (sessionToken && playedGame) {
      // Analytics-only: highest hint tier revealed today for this game, from the
      // shared FAR-198 budget key (in-game HintControl + the /challenge/hints
      // page both spend it). Free — never an input to score math.
      let hintsUsed = 0;
      try {
        const v = parseInt(localStorage.getItem(`faraday_hints_${TODAY}_${playedGame}`) || "0", 10);
        if (!Number.isNaN(v)) hintsUsed = Math.max(0, Math.min(3, v));
      } catch { /* storage disabled */ }
      // Authoritative score write — enforces one-attempt-per-day + leaderboard_daily.
      fetch(`/api/score`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          token: sessionToken,
          gameType: playedGame,
          score,
          result: "win",
          hintsUsed,
        }),
      })
        .then(r => r.json())
        .then(data => {
          if (data?.alreadyPlayed) return; // idempotent — already counted
          if (typeof data?.playStreak === "number") setStreak(data.playStreak);
          if (typeof data?.runningDailyTotal === "number") {
            setLastDailyTotal(data.runningDailyTotal);
          }
          refreshLeaderboard();
        })
        .catch(() => { /* offline — keep optimistic counters */ });
    }
    // Show social gate after first game only for truly anonymous sessions.
    // Check localStorage directly — subscriber-state may not have resolved yet
    // when the first game completes, leaving email null for registered users.
    let hasSession = false;
    try { hasSession = !!localStorage.getItem(SESSION_STORAGE_KEY); } catch {}
    if (!email && !hasSession && gamesPlayed === 0) {
      setGateReason("leaderboard");
      setScreen("gate");
    } else {
      setScreen("lobby");
    }
  }

  function onAuthComplete(token, subscriber) {
    setSessionToken(token);
    setEmail(subscriber.email);
    if (subscriber.handle) setHandle(subscriber.handle);
    try { localStorage.setItem(SESSION_STORAGE_KEY, token); } catch {}
    try { localStorage.setItem(EMAIL_STORAGE_KEY, subscriber.email); } catch {}
    try { if (subscriber.handle) localStorage.setItem(HANDLE_STORAGE_KEY, subscriber.handle); } catch {}
    try { if (subscriber.id) localStorage.setItem(SUBSCRIBER_ID_KEY, subscriber.id); } catch {}
    setScreen("lobby");
  }

  function onGateDismiss() {
    setScreen("lobby");
  }

  const GAME_COMPONENTS = {
    "Rackl":       GameRackl,
    "Signal Drop": GameSignalDrop,
    "The Stack":   GameStack,
    "Circuit":     GameCircuit,
    "The Brief":   GameBrief,
    "Dark Fiber":  GameDarkFiber,
    "Frequency":   GameFrequency,
  };

  // Display handle: canonical handle if known, else the email local-part as a
  // graceful fallback (no fabricated identity — Precision brand value).
  const displayHandle = handle || (email ? email.split("@")[0] : null);

  // Display totals: prefer the authoritative server figures; fall back to the
  // running daily total, then the local per-day sum (for guests / offline).
  const todayTotal  = serverToday  != null ? serverToday  : (lastDailyTotal || todayScore);
  const seasonTotal = serverSeason != null ? serverSeason : (lastDailyTotal || todayScore);

  // Header dropdown menus — edit text/links in buildHeaderMenus (defined above).
  // All Games routes through the same confirm-before-discard flow as the in-game
  // switcher: picking another game mid-puzzle asks first instead of losing progress.
  const headerMenus = buildHeaderMenus({
    email,
    activeGame: screen === "game" ? activeGame : null,
    onGame: (type) => {
      const inLiveGame = screen === "game" && activeGame && !dailyResults[activeGame] && !todayCompletions[activeGame];
      if (inLiveGame && activeGame !== type) requestSwitch(type);
      else startGame(type);
    },
    onSignIn:   () => { setGateReason("default"); setScreen("gate"); },
    onAccount:  openAccount,
    onSettings: openAccount,
    onSignOut:  handleSignOut,
  });

  return (
    <div style={{ minHeight:"100vh", background: (screen === "lobby" || screen === "account") ? C.cream : C.bg, color:C.black, ...sans }}>
      {showSplash && <SplashScreen onEnter={dismissSplash} />}
      <GameIconDefs />

      {/* ── MASTHEAD — gold rule · forest banner · gold rule ── */}
      <div style={{ height:"2px", background:C.gold }} />
      <header style={{ background:C.forest, position:"sticky", top:0, zIndex:50 }}>
        <div className="fdc-header-inner">
          {/* Wordmark flush left — no bounding box / icon (per header overhaul).
              Clickable → lobby: the old grid menu's "Today's Puzzle" item was the
              way home; the wordmark now carries that (mirrors SiteHeaderNav). */}
          <button
            type="button"
            onClick={() => setScreen("lobby")}
            aria-label="Daily Challenge lobby"
            style={{ lineHeight:1.25, background:"none", border:"none", padding:0, cursor:"pointer", textAlign:"left", WebkitTapHighlightColor:"transparent" }}
          >
            <b style={{ ...serif, fontWeight:700, fontSize:"clamp(16px,1.5vw,22px)", color:C.white, letterSpacing:"0.04em" }}>Faraday</b>
            <span style={{ display:"block", ...mono, fontSize:"clamp(11px,0.85vw,13px)", letterSpacing:"0.18em", color:C.sage }}>DAILY CHALLENGE</span>
          </button>

          {/* Right cluster: ambient status (handle + Today/Season) then the five
              icon-dropdown triggers. Status is hidden on the narrowest phones
              (≤430px) where the icon row fills the strip — the totals still show on
              the Account page and in the Account dropdown's Streak & Stats. */}
          <div style={{ marginLeft:"auto", display:"flex", alignItems:"center", gap:"16px", flexWrap:"nowrap" }}>
            {displayHandle && !navIconsLabelHidden && (
              <div style={{ display:"flex", alignItems:"center", gap:"14px", minWidth:0 }}>
                <button
                  type="button"
                  onClick={() => { if (!email) { setGateReason("default"); setScreen("gate"); } else { openAccount(); } }}
                  title="Account"
                  style={{
                    ...mono, fontSize:"clamp(12px,1vw,14px)", fontWeight:700,
                    color:C.gold, letterSpacing:"0.04em",
                    background:"transparent", border:"none", cursor:"pointer",
                    padding:"4px 6px", whiteSpace:"nowrap",
                    WebkitTapHighlightColor:"transparent",
                  }}
                >
                  @{displayHandle}
                </button>
                <div style={{ display:"flex", gap:"16px", alignItems:"flex-start" }}>
                  <div style={{ textAlign:"center", lineHeight:1.1 }}>
                    <div style={{ ...sans, fontSize:"15px", fontWeight:800, color:C.gold }}>{(todayTotal || 0).toLocaleString()}</div>
                    <div style={{ ...mono, fontSize:"8px", letterSpacing:"0.08em", textTransform:"uppercase", color:C.sage, marginTop:"2px" }}>Today&rsquo;s Total Score</div>
                  </div>
                  <div style={{ textAlign:"center", lineHeight:1.1 }}>
                    <div style={{ ...sans, fontSize:"15px", fontWeight:800, color:C.white }}>{(seasonTotal || 0).toLocaleString()}</div>
                    <div style={{ ...mono, fontSize:"8px", letterSpacing:"0.08em", textTransform:"uppercase", color:C.sage, marginTop:"2px" }}>Season Total Score</div>
                  </div>
                </div>
              </div>
            )}
            <HeaderIconNav menus={headerMenus} />
          </div>
        </div>
      </header>
      <div style={{ height:"2px", background:C.gold }} />

      {/* ── BODY ── */}
      <main style={{ maxWidth:"820px", margin:"0 auto", padding:"0 20px" }}>

        {/* LOBBY */}
        {screen === "lobby" && (
          <div className="ca">
            <div style={{ padding:"44px 0 8px" }}>
              <h1 style={{ ...serif, fontWeight:700, fontSize:"clamp(32px,7vw,44px)",
                letterSpacing:"-0.01em", color:C.black, margin:0 }}>
                Test your edge.
              </h1>
              <div className="double-rule" aria-hidden="true" />
              <p style={{ fontSize:"15px", color:"rgba(20,18,16,0.68)", marginTop:"16px",
                maxWidth:"52ch", lineHeight:1.6, ...sans }}>
                Seven daily intelligence challenges for people who work in and around the AI data
                center economy. Free to play. Two minutes.
              </p>
            </div>

            {/* Game tiles — neon pictograms on forest tiles, white card on cream */}
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(330px,1fr))",
              gap:"14px", padding:"28px 0 8px" }}>
              {GAME_CONFIGS.map(config => {
                const attempt = todayCompletions[config.type] || dailyResults[config.type];
                return (
                  <GameTile key={config.type} config={config}
                    played={!!attempt}
                    priorScore={attempt?.score || 0}
                    onPlay={() => startGame(config.type)} />
                );
              })}
            </div>

            {/* Subscriber stat line — real Supabase results only (no mock
                engagement stats): play streak and today's completion count
                come from get-subscriber-state / complete-puzzle. */}
            {email && (
              <div style={{ marginTop:"18px", ...mono, fontSize:"12px", color:C.forest }}>
                {displayHandle ? <><b>@{displayHandle}</b> · </> : null}
                {optedOut ? "Left the game — " : ""}Signed in as {email} · {streak}-day streak · Score: {lastDailyTotal}
                · {Object.keys(todayCompletions).length}/7 puzzles today{" · "}
                <a href="/account" style={{ color:C.deepAmber, textDecoration:"underline" }}>Account &amp; settings</a>
              </div>
            )}

            {/* Team leaderboard — real per-player score, wired via DB trigger */}
            <TeamLeaderboard
              leaderboard={leaderboard}
              myTeam={myTeam}
              signedIn={!!email && !optedOut}
              busy={teamBusy}
              error={teamError}
              onCreate={(name) => teamAction("create", { name })}
              onJoin={(code) => teamAction("join", { code })}
              onLeave={() => teamAction("leave", {})}
            />

            {/* Faraday tagline card — forest-green closing statement, final element
                on the lobby. Replaces the former "From Faraday Intelligence"
                cross-sell band; deliberately carries NO outbound links to any
                Faraday Intelligence property (copy-only, brand-voiced). */}
            <div style={{ background:C.forest, borderRadius:"10px",
              padding:"28px 24px", margin:"28px 0 0" }}>
              <p style={{ ...sans, fontWeight:700, fontSize:"22px", lineHeight:1.35,
                color:C.cream, margin:0 }}>
                <span style={{ color:C.gold }}>1891 → 2080.</span> We read the signals and trajectory on a 189 year timescale. The news cycle operates on yesterday’s press announcement and next quarter’s chip forecast.
              </p>
              <p style={{ ...sans, fontWeight:400, fontSize:"15px", lineHeight:1.7,
                color:C.cream, opacity:0.85, margin:"16px 0 0" }}>
                The oldest generators powering our grid came online in 1891, and are still working today. The water and load forecasts that are real constraints run to 2080. Faraday is actively tracking the whole span across more than twenty intelligence domains and aligned to jurisdiction — not the press release. The arc, and the collisions.
              </p>
              <p style={{ ...serif, fontStyle:"italic", fontSize:"16px", color:C.gold,
                margin:"20px 0 0", paddingTop:"16px",
                borderTop:"1px solid rgba(196,146,42,0.25)" }}>
                Faraday, your unfair advantage.
              </p>
            </div>
          </div>
        )}

        {/* GAME */}
        {screen === "game" && activeGame && (() => {
          const GameComponent = GAME_COMPONENTS[activeGame];
          // Prefer the live puzzle from Airtable; fall back to mock per-game.
          const puzzle = livePuzzles[activeGame] || PUZZLE_DATA[activeGame];
          const config = GAME_CONFIGS.find(c=>c.type===activeGame);
          if (!GameComponent || !puzzle) return <div style={{ color:C.red }}>Puzzle not found</div>;
          const priorResult = dailyResults[activeGame];
          return (
            <div className="ca" style={{ paddingTop:"28px" }}>
              {/* Game header */}
              <div style={{ marginBottom:"20px" }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"6px" }}>
                  <div style={{ display:"flex", alignItems:"center", gap:"10px" }}>
                    <GameIcon game={activeGame} size={32} />
                    <div>
                      <span style={{ fontSize:"16px", fontWeight:700, color:C.white, ...serif }}>{activeGame}</span>
                      {puzzle.__publicId && (
                        <span style={{ fontSize:"11px", color:C.muted, marginLeft:"8px", letterSpacing:"0.04em", ...mono }}>· {puzzle.__publicId}</span>
                      )}
                    </div>
                  </div>
                  <div style={{ display:"flex", gap:"8px", alignItems:"center", flexWrap:"wrap" }}>
                    <span style={{ fontSize:"11px", color:C.muted, background:"rgba(255,255,255,0.04)",
                      border:`1px solid ${C.border}`, padding:"3px 8px", borderRadius:"3px", ...mono }}>
                      {puzzle.domain}
                    </span>
                    <span style={{ fontSize:"11px", color:C.muted, ...mono }}>{config.time}</span>
                  </div>
                </div>
                {/* Signal Drop's puzzle.name IS the answer word (e.g. "SOVEREIGNTY"),
                    so it must never render in-game — it would reveal the solution.
                    Other games use a descriptive name that is safe to show. */}
                {activeGame !== "Signal Drop" && (
                  <div style={{ fontSize:"11px", color:C.muted, ...mono }}>{puzzle.name}</div>
                )}

                {/* Identity */}
                <div style={{ display:"flex", alignItems:"center", gap:"10px", marginTop:"10px", flexWrap:"wrap" }}>
                  <span style={{ fontSize:"11px", ...mono, color: displayHandle ? C.goldLight : C.muted }}>
                    {displayHandle ? `@${displayHandle}` : "Playing as guest"}
                  </span>
                </div>

                {/* Game switcher — only show in live game, not replay */}
                {!priorResult && <GameSwitcher current={activeGame} onSwitch={requestSwitch} />}
              </div>

              {/* In-progress switch confirm */}
              {pendingSwitch && (
                <div style={{ marginBottom:"16px", background:"rgba(245,158,11,0.08)",
                  border:"1px solid rgba(245,158,11,0.35)", borderRadius:"8px", padding:"12px 14px",
                  display:"flex", alignItems:"center", gap:"12px", flexWrap:"wrap" }}>
                  <span style={{ fontSize:"12px", color:C.amber, ...mono, flex:"1 1 200px" }}>
                    Switch to {pendingSwitch}? Your progress on {activeGame} will be lost.
                  </span>
                  <div style={{ display:"flex", gap:"8px" }}>
                    <Btn small variant="ghost" onClick={() => setPendingSwitch(null)}>Stay</Btn>
                    <Btn small onClick={confirmSwitch}>Switch →</Btn>
                  </div>
                </div>
              )}

              {/* Replay or live game */}
              {priorResult ? (
                <GameReplay
                  gameType={activeGame}
                  snapshot={priorResult}
                  puzzle={puzzle}
                  onBack={() => setScreen("lobby")}
                />
              ) : (
                // Key on the puzzle identity so the game remounts when the live
                // Airtable puzzle replaces the mock fallback (the fetch resolves
                // after mount). Without this, useState initializers that build
                // tiles/order/shuffled-defs from the mock puzzle never re-run,
                // leaving stale tiles while the title/hints/scoring use the live
                // puzzle. Falls back to a per-game key when there is no publicId.
                <GameComponent key={puzzle.__publicId || `mock-${activeGame}`} puzzle={puzzle} streak={streak} onComplete={onGameComplete} dailyTotal={lastDailyTotal} />
              )}
            </div>
          );
        })()}

        {/* SOCIAL GATE */}
        {screen === "gate" && (
          <div className="ca" style={{ maxWidth:"420px", margin:"0 auto", paddingTop:"40px" }}>
            <div style={{ background:C.forestMid, border:"1px solid rgba(248,245,240,.12)",
              borderRadius:"12px", padding:"28px" }}>
              <SocialGate trigger={gateReason} onComplete={onAuthComplete} onDismiss={onGateDismiss} />
            </div>
          </div>
        )}

        {/* ACCOUNT */}
        {screen === "account" && (
          <AccountPage
            email={email}
            handle={handle}
            sessionToken={sessionToken}
            streak={streak}
            todayScore={todayTotal}
            seasonScore={seasonTotal}
            dailyResults={dailyResults}
            onBack={() => setScreen(prevScreen === "account" ? "lobby" : prevScreen)}
            onSignOut={handleSignOut}
            onHandleChange={setHandle}
            onSignIn={() => { setGateReason("default"); setScreen("gate"); }}
          />
        )}
      </main>
    </div>
  );
}
